INSERT INTO `information_wizards` (`id`, `title`, `field_fee_structure_files`, `delta`, `field_noc_master_link`, `field_wizard_category`, `field_wizard_department`, `field_wizard_fee_text`, `field_wizard_noc_name`, `field_wizard_notification`, `delta_1`, `field_wizard_process`, `field_wizard_required_documents`, `field_wizard_timeline`) VALUES
(1, '<a href=\"/node/38251\" hreflang=\"en\">Legal-Importer</a>', '', 0, '<a href=\"/node/37460\" hreflang=\"en\">OTH-LM4</a>', 'Special Services', 'Legal Metrology', '<p><span><span>Rs.500/-</span></span></p>', 'Registration of Importer of pre-packed commodities', '', 0, '<ul>\n	<li><span><span><span>Submitting application through SWAAGAT portal (URL : swaagat.tripura.gov.in).</span></span></span></li>\n	<li><span><span><span>Uploading required documents.</span></span></span></li>\n	<li><span><span><span>Scrutiny of application and documents by the concerned Inspector.</span></span></span></li>\n	<li><span><span><span>Intimation of deficiencies, if any, to the applicant for removal of the same.</span></span></span></li>\n	<li><span><span><span>Inspection of the premises.</span></span></span></li>\n	<li><span><span><span>Uploading of reports / recommendation of the Inspector for final decision to be taken by the Registering Authority (Controller, Legal Metrology).</span></span></span></li>\n	<li><span><span><span>Review by the Registering Authority (Controller, Legal Metrology) and issue of Registration Certificate in the eligible cases to be viewed / downloaded by the applicant using his/her log in.</span></span></span></li>\n</ul>', '<ol>\n	<li><span><span><span>Document pertaining to possession of land / premises of business</span></span></span></li>\n	<li><span><span><span>NOC from the owner of the land / building if taken on rental basis or lease</span></span></span></li>\n	<li><span><span><span>Proof of nationality</span></span></span></li>\n	<li><span><span><span>Registration with concerned authorities in case of companies/co-operative societies/SHGs</span></span></span></li>\n	<li><span><span><span>Memorandum of Articles in case of companies / partnership deed in case of partnership  firms</span></span></span></li>\n	<li><span><span><span>Certificate / License of Importer</span></span></span></li>\n	<li><span><span><span>Site plan (self signed hand sketch showing location of the unit)</span></span></span></li>\n</ol>', '<p>21 days</p>'),
(2, '<a href=\"/node/38250\" hreflang=\"en\">Legal-Dealer</a>', '', 0, '<a href=\"/node/37459\" hreflang=\"en\">OTH-LM2</a>', 'Special Services', 'Legal Metrology', '<p><span><span><span><span><span>a) For new license – Rs.100/- </span></span></span></span></span></p>\n\n<p><span><span><span><span><span>b) For renewal       -  Rs.100/-</span></span></span></span></span></p>', 'Licensing of dealers of weight or measure', '', 0, '<ul>\n	<li><span><span><span><span><span>Submitting application through SWAAGAT portal (URL : swaagat.tripura.gov.in)</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Uploading required documents.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Scrutiny of application and documents by the concerned Inspector.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Intimation of deficiencies, if any, to the applicant for removal of the same.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Inspection of the premises.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Uploading of reports / recommendation of the Inspector for final decision to be taken by the Licensing Authority (Controller, Legal Metrology).</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Review by the Licensing Authority (Controller, Legal Metrology) and issue of license in the eligible cases to be viewed / downloaded by the applicant using his/her log in.</span></span></span></span></span></li>\n</ul>\n\n<p> </p>\n\n<p><span><span><span><strong><span><span>Procedure for renewal of license</span></span></strong></span></span></span></p>\n\n<p><span><span><span><strong> </strong><span><span>There shall be provision for <strong>Auto-renewal</strong> of the license.</span></span></span></span></span></p>\n\n<ul>\n	<li><span><span><span><span><span>The licensee shall have to make online payment of prescribed renewal fee through SWAAGAT Portal within the timeline specified under The Tripura Legal Metrology (Enforcement) Rules, 2011.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>On payment of prescribed fee within the specified timeline the license shall be auto-renewed by the system.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>However, the licensee shall maintain records / registers of weight or measure sold as required under the Rules and submit annual return to the Controller, Legal Metrology in this regard.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>The licensee shall inform the Licensing Authority with supporting documents in respect of any change in address, constitution of firm etc. </span></span></span></span></span></li>\n</ul>', '<ol>\n	<li><span><span><span><span><span>Proof of legal title of the premises (copy of the sale deed/lease deed/allotment letter/ property tax receipt), Rent receipt / NOC from the owner of the land (as applicable)</span></span></span></span></span></li>\n	<li><span><span><span>Proof of nationality</span></span></span></li>\n	<li><span><span><span>Memorandum of articles in case of Private Limited Company and Limited Company</span></span></span></li>\n	<li><span><span><span><span>Details of manufacturer’s trade mark / monogram and his licence number/ Registration of Importer of Weights and Measures /Approval of model issued by Central Government for weight or measure imported into India (If intend to import weight or measure from outside state / country)</span></span></span></span></li>\n	<li><span><span><span>  <span><span>Site plan (self signed hand sketch showing location of the unit)</span></span></span></span></span></li>\n</ol>', '<p>21 Days</p>'),
(3, '<a href=\"/node/38249\" hreflang=\"en\">Legal-Repairer</a>', '', 0, '<a href=\"/node/37458\" hreflang=\"en\">OTH-LM3</a>', 'Special Services', 'Legal Metrology', '<p><span><span><span><span><span>(a) For new license – Rs.200/- </span></span></span></span></span></p>\n\n<p><span><span><span><span><span>(b) For renewal       -  Rs.200/-</span></span></span></span></span></p>', 'Licensing of repairers of weight or measure', '', 0, '<ul>\n	<li><span><span><span><span><span>Submitting application through SWAAGAT portal (URL : swaagat.tripura.gov.in)</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Uploading required documents.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Scrutiny of application and documents by the concerned Inspector.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Intimation of deficiencies, if any, to the applicant for removal of the same.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Inspection of the premises.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Uploading of reports / recommendation of the Inspector for final decision to be taken by the Licensing Authority (Controller, Legal Metrology).</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Review by the Licensing Authority (Controller, Legal Metrology) and issue of license in the eligible cases to be viewed / downloaded by the applicant using his/her log in.</span></span></span></span></span></li>\n</ul>\n\n<p> </p>\n\n<p><span><span><span><strong><span><span>Procedure for renewal of license</span></span></strong></span></span></span></p>\n\n<p><span><span><span><strong> </strong><span><span>There shall be provision for <strong>Auto-renewal</strong> of the license.</span></span></span></span></span></p>\n\n<ul>\n	<li><span><span><span><span><span>The licensee shall have to make online payment of prescribed renewal fee through SWAAGAT Portal within the timeline specified under The Tripura Legal Metrology (Enforcement) Rules, 2011.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>On payment of prescribed fee within the specified timeline the license shall be auto-renewed by the system.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>However, the licensee shall maintain records / registers of weight or measure repaired as required under the Rules and submit annual return to the Controller, Legal Metrology in this regard.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>The licensee shall inform the Licensing Authority with supporting documents in respect of any change in address, constitution of firm etc. </span></span></span></span></span></li>\n</ul>', '<ol>\n	<li><span><span><span><span><span>Proof of legal title of the premises (copy of the sale deed/lease deed/allotment letter/ property tax receipt), Rent receipt / NOC from the owner of the land (as applicable)</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Proof of nationality</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Memorandum of articles in case of Private Limited Company and Limited Company</span></span></span></span></span></li>\n	<li><span><span><span><span><span>List of testing equipment/tools/accessories</span></span></span></span></span></li>\n	<li><span><span><span><span><span>List of loan articles</span></span></span></span></span></li>\n	<li><span><span><span><span><span>List of skilled / semi-skilled / un-skilled workers</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Experience Certificate (At least for one year in the field of repairing of the items for which license applied for in the name of Proprietor / Skilled worker / Partner / Director of the firm or Certificate from I.T.I. in Instrument Mechanic &amp; Electronics.) </span></span></span></span></span></li>\n	<li><span><span><span><span><span>Site plan (self signed hand sketch showing location of the unit)</span></span></span></span></span></li>\n</ol>', '<p>21 Days</p>'),
(4, '<a href=\"/node/38248\" hreflang=\"en\">Legal-Packer</a>', '', 0, '<a href=\"/node/21298\" hreflang=\"en\">OTH-LM1</a>', 'Special Services', 'Legal Metrology', '<p><span><span>Rs.500/-</span></span></p>', 'Registration of Packer ', '', 0, '<ul>\n	<li><span><span><span>Submitting application through SWAAGAT portal.</span></span></span></li>\n	<li><span><span><span>Uploading required documents.</span></span></span></li>\n	<li><span><span><span>Scrutiny of application and documents by the concerned Inspector.</span></span></span></li>\n	<li><span><span><span>Intimation of deficiencies, if any, to the applicant for removal of the same.</span></span></span></li>\n	<li><span><span><span>Allocation of Inspector for inspection of the premises if the application is found complete in all respect.</span></span></span></li>\n	<li><span><span><span>Uploading of reports / recommendation of the Inspector for final decision to be taken by the Registering Authority (Controller, Legal Metrology).</span></span></span></li>\n	<li><span><span><span>Review by the Registering Authority (Controller, Legal Metrology) and issue of signed Registration Certificate in the eligible cases to be viewed / downloaded by the applicant using his log in.</span></span></span></li>\n</ul>', '<ol>\n	<li><span><span><span>Document pertaining to possession of land / premises of business</span></span></span></li>\n	<li><span><span><span>NOC from the owner of the land / building if taken on rental basis or lease</span></span></span></li>\n	<li><span><span><span>Proof of nationality</span></span></span></li>\n	<li><span><span><span>Tax Clearance Certificate / GST Registration, if registered</span></span></span></li>\n	<li><span><span><span>Trade licence where applicable</span></span></span></li>\n	<li><span><span><span>Certificate from local bodies / panchayat if situated outside AMC/MC/NAA</span></span></span></li>\n	<li><span><span><span>Registration with concerned authorities in case of companies/co-operative societies/SHGs</span></span></span></li>\n	<li><span><span><span>Memorandum of Articles in case of companies / partnership deed in case of partnership  firms</span></span></span></li>\n	<li><span><span><span>Power of Attorney/Authorization in favour of the signatory in the application in case of companies/partnership  firms /co-operative societies/SHGs/HUF</span></span></span></li>\n	<li><span><span><span>Site plan</span></span></span></li>\n	<li><span><span><span>Treasury challan / receipt generated online in support of depositing prescribed fee.</span></span></span></li>\n</ol>', '<p>21 Days</p>'),
(5, '<a href=\"/node/38247\" hreflang=\"en\">Legal-Manufacture</a>', '', 0, '<a href=\"/node/13648\" hreflang=\"en\">CFO-LM1</a>', 'Consent for Operation', 'Legal Metrology', '<p><span><span><span>(a) For new licence – Rs.500/- </span></span></span></p>\n\n<p><span><span><span>(b) For re-newal      -  Rs.500/-</span></span></span></p>', 'Licensing of manufacturers of weight or measure', '', 0, '<ul>\n	<li><span><span><span>Submitting application through SWAAGAT portal.</span></span></span></li>\n	<li><span><span><span>Uploading required documents.</span></span></span></li>\n	<li><span><span><span>Scrutiny of application and documents by the concerned Inspector.</span></span></span></li>\n	<li><span><span><span>Intimation of deficiencies, if any, to the applicant for removal of the same.</span></span></span></li>\n	<li><span><span><span>Allocation of Inspector for inspection of the premises if the application is found complete in all respect.</span></span></span></li>\n	<li><span><span><span>Uploading of reports / recommendation of the Inspector for final decision to be taken by the Licencing Authority (Controller, Legal Metrology).</span></span></span></li>\n	<li><span><span><span>Review by the Licencing Authority (Controller, Legal Metrology) and issue of signed licence in the eligible cases to be viewed / downloaded by the applicant using his log in.</span></span></span></li>\n</ul>', '<ol>\n	<li><span><span><span>Proof of legal title of the premises (attested copy of the sale deed/lease deed/allotment letter/ property tax receipt</span></span></span></li>\n	<li><span><span><span>Rent receipt / NOC from the owner of the land </span></span></span></li>\n	<li><span><span><span>Proof of nationality</span></span></span></li>\n	<li><span><span><span>Tax Clearance Certificate / GST Registration, if registered</span></span></span></li>\n	<li><span><span><span>Trade licence where applicable</span></span></span></li>\n	<li><span><span><span>Certificate from local bodies / panchayat if situated outside AMC/MC/NAA</span></span></span></li>\n	<li><span><span><span>Copy regarding constitution of the firm</span></span></span></li>\n	<li><span><span><span>Experience certificate</span></span></span></li>\n	<li><span><span><span>Tools and equipment list</span></span></span></li>\n	<li><span><span><span>List of testing equipment</span></span></span></li>\n	<li><span><span><span>Copy of the literature of the items to be manufactured</span></span></span></li>\n	<li><span><span><span>Proof of financial status</span></span></span></li>\n	<li><span><span><span>Proof of power load sanctioned / installed by the concerned Authority</span></span></span></li>\n	<li><span><span><span>Copy of permanent SSI Registration</span></span></span></li>\n	<li><span><span><span>List of skilled / unskilled workers with their names and addresses</span></span></span></li>\n	<li><span><span><span>Site plan</span></span></span></li>\n	<li><span><span><span>Treasury challan/receipt generated online in support of depositing prescribed fee<strong>.</strong></span></span></span></li>\n</ol>', '<p>21 Days</p>'),
