(10, '<a href=\"/node/38221\" hreflang=\"en\">SLT-State-Levies-Taxes</a>', '', 0, '', 'Standard Process', 'Levies and Local Taxes', '', 'State Levies &amp; Local Taxes', '', 4, '', '', ''),
(11, '<a href=\"/node/38221\" hreflang=\"en\">SLT-State-Levies-Taxes</a>', '', 0, '', 'Standard Process', 'Levies and Local Taxes', '', 'State Levies &amp; Local Taxes', '', 5, '', '', ''),
