(13, '<a href=\"/node/38221\" hreflang=\"en\">SLT-State-Levies-Taxes</a>', '', 0, '', 'Standard Process', 'Levies and Local Taxes', '', 'State Levies &amp; Local Taxes', '', 7, '', '', ''),
(14, '<a href=\"/node/38221\" hreflang=\"en\">SLT-State-Levies-Taxes</a>', '', 0, '', 'Standard Process', 'Levies and Local Taxes', '', 'State Levies &amp; Local Taxes', '', 8, '', '', ''),
(15, '<a href=\"/node/38238\" hreflang=\"en\">Partnership</a>', '', 0, '', 'Special Services', 'Partnership Firm Registration (I &amp; C)', '<p><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>Fee of Rs.3/- (Rupees three) for Registration and fee of Rs.2/- (Rupees two) for inspection, total Rs.5/- (Rupees five) has to be paid through online portal.</span></span></span></span></span></p>', 'Partnership Firm Registration', '', 0, '<ol>\n	<li><span><span><strong><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>Application for Partnership Firm Registration: </span></span></strong></span></span></li>\n</ol>\n\n<ul>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>The law relating to a partnership firm is contained in the <strong>Indian Partnership Act, 1932</strong>.</span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>The Proponent shall submit Application on-line through the SWAAGAT portal. (swaagat.tripura.gov.in) </span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>The applications must be filled as per instructions and submitted with the required documents. </span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>When the application is filled up and submitted, a message/ e-mail will be sent to scrutiny officer. </span></span></span></span></span></li>\n</ul>\n\n<ol start=\"2\">\n	<li><span><span><strong><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>Processing of the Application: </span></span></strong></span></span></li>\n</ol>\n\n<ul>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>If the application is found to be in order and all the attached documents is meeting requirements, then the registration will be done within 7 days.</span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>If any query raised by Scrutiny officer, the 7 days timer will stop until the query is cleared. </span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>After scrutiny, the application will send to approval authority.</span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>Once approved the certificate will also be issued and a message/e-mail will be send to the applicant and the applicant can download it through the SWAAGAT portal.</span></span></span></span></span></li>\n</ul>', '<ol>\n	<li><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>Registered Partnership Deed.</span></span></span></span></li>\n	<li><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>Up-to-date License/Approvals/Permits (as applicable).</span></span></span></span></li>\n	<li><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>Aadhar, PAN Card, Voter ID of all the partners.</span></span></span></span></li>\n	<li><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>Passport Size photographs of all partners.</span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>Relevant document (khatian/parcha)/ Registered land lease deed to establish address of the principal place of business or any other place(s) where farm carries on Business.</span></span></span></span></span></li>\n</ol>', '<p><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>Within 7 days from receipt of original byelaws, rules and other papers which are submitted through online and also listed in the checklist.</span></span></span></span></p>'),
(16, '<a href=\"/node/38300\" hreflang=\"en\">PTax-Registration</a>', '', 0, '<a href=\"/node/13956\" hreflang=\"en\">OTH-PT2</a>', 'Other Services', 'Profession Tax', '<p><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span><span>No fee is required for obtaining Profession Tax Registration Certificate</span></span></span></span></p>', 'Application for Registration', '', 0, '<ul>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span><span>To file application for Profession Tax Registration as per The Tripura Professions, Trades, Callings and Employments Taxation Act, 1997, under EODB initiative the applicant should visit the Tripura SWAAGAT Web-Portal (</span></span></span></span><strong><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span><span>https://swaagat.tripura.gov.in/#/page/home</span></span></span></span></strong><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span><span>).</span></span></span></span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span><span>A list of Jurisdiction is provided as a link so that the applicant can view and select appropriate jurisdiction.</span></span></span></span></span></span></span></span></li>\n</ul>\n\n<p><span><span><span><span><strong><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span><span>Processing of the Application</span></span></span></span></strong></span></span></span></span></p>\n\n<ul>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span><span>The application submitted is verified online and if any discrepancy is found in application the scrutiny officer may raise a query with valid reason. </span></span></span></span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span><span>Subsequently the report of scrutiny is also submitted through online before the approval authority for next course of action.</span></span></span></span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span><span>The application is approved if the report is found in order, otherwise it is rejected with grounds and the same is sent to the applicant through SMS/email.</span></span></span></span></span></span></span></span></li>\n</ul>\n\n<p><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span><span>The applicant can download the Registration Certificate from the system once it is approved. </span></span></span></span></p>', '<ul>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span><span>Mobile Number</span></span></span></span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span><span>Email ID</span></span></span></span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span><span>PAN</span></span></span></span></span></span></span></span></li>\n</ul>', '<p>30 Days</p>'),
(17, '<a href=\"/node/38298\" hreflang=\"en\">PWD-DWS</a>', '', 0, '<a href=\"/node/13642\" hreflang=\"en\">CFE-WPD1</a>', 'Consent for Establishment', 'PWD (Drinking water and Sanitation)', '<p><span><span><span><span>Water charges circulated vide Notification No. F. 6(21)/CE/DWS/E/2011 dated 17-05-2014 of the Deputy Secretary, PWD (DWS), Govt. of Tripura.</span></span></span></span></p>', 'Application for Water Supply Connection', '', 0, '<ol>\n	<li><span><span><span><span>The industrial user shall submit application through SWAAGAT portal published in the public domain under the URL: swaagat.tripura.gov.in.</span></span></span></span></li>\n	<li><span><span><span><span>The applications will be pre-scrutinized online at SWAAGAT to verify whether the application is in order with all requisite information and enclosures.</span></span></span></span></li>\n	<li><span><span><span><span>The deficiencies in the application if any found during scrutiny will be informed to the applicant through online.</span></span></span></span><span><span> </span></span></li>\n</ol>\n\n<p> </p>\n\n<p><span><span><strong><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>Processing of the Application</span></span></strong><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>:</span></span></span></span></p>\n\n<ol>\n	<li><span><span><span><span>The application if found in order will be sent to the concerned Executive Engineer of DWS Division.</span></span></span></span></li>\n	<li><span><span><span><span>A field inspection shall be undertaken by the concerned Executive Engineer or by his authorized representative to ascertain the feasibility for providing the water supply connection applied for.  </span></span></span></span></li>\n	<li><span><span><span><span>If extension of water supply connection is found feasible the concerned Executive Engineer of DWS Division shall upload the estimate for installation charge along with the amount of connection fee. However, if extension of the water supply connection is not found feasible as per actual field condition a certificate regarding non-availability shall be uploaded by the concerned Executive Engineer.</span></span></span></span></li>\n	<li><span><span><span><span>The estimated cost for installation charge along with the connection fee to be deposited for extension of the water supply connection will automatically be shared with the applicant through SWAAGAT portal published in the public domain.</span></span></span></span></li>\n	<li><span><span><span><span>After depositing the installation charge as per estimate and connection fee by the applicant the respective DWS Division will provide the water supply connection within the prescribed timelines. Necessary arrangement for storage of supplied water including internal plumbing works shall be made by the applicant at his own cost and risk. </span></span></span></span></li>\n	<li><span><span><span><span>After extension of the water supply connection as applied for, a certificate to this effect will be issued by the concerned Executive Engineer.</span></span></span></span></li>\n</ol>', '<ol>\n	<li><span><span><span><span>Land Registration Deed of the premises to which water supply connection to be extended.</span></span></span></span></li>\n	<li><span><span><span><span>Partnership details (or) Articles of Association (AOA) in support of authority of the applicant. </span></span></span></span></li>\n	<li><span><span><span><span>Document in support of total number of workers for whom water supply connection is applied for.</span></span></span></span></li>\n</ol>', '<ol>\n	<li><span><span><span><span>Feasibility study for extension of drinking water supply connection and uploading of estimate / non-feasibility certificate on or before 14 (fourteen) days w.e.f. the date of uploading of application.</span></span></span></span><span><span> </span></span></li>\n	<li><span><span><span><span>Extension of drinking water supply connection on or before 14 (fourteen) days from the date of depositing installation charge as per estimate and connection fee.</span></span></span></span></li>\n</ol>'),
(18, '<a href=\"/node/39414\" hreflang=\"en\">RD-Panchayat</a>', '', 0, '', 'Standard Process', 'RD (Panchayat Department)', '', 'No Objection Certificate', '', 0, '<p><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>No provision for issue of No Objection Certificate for setting up of ne Industrial units in Gram Panchayats.</span></span></span></p>', '', ''),
(19, '<a href=\"/node/39404\" hreflang=\"en\">Pollution - Plastic Waste</a>', '', 0, '', 'Other Services', 'Tripura State Pollution Control Board', '<ul>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>For  plastic recycler Rs. 13,000/-</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>For plastic producer/ manufacture/ brand owner Rs. 10000/-</span></span></span></span></span></span></li>\n</ul>', 'Registration/ Renewal  under the Plastic Waste (Management &amp; Handling) Rules, 2011 ', '', 0, '<ol>\n	<li><span><span><span><strong><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Application</span></span></span></strong></span></span></span>\n	<ol>\n		<li><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>The Proponent shall submit Application on-line through the SWAAGAT portal. (swaagat.tripura.gov.in) </span></span></span></span></li>\n		<li><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>The applications must be filled as per instructions and submitted with the required documents. </span></span></span></span></li>\n		<li><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>When the application is filled up and submitted, a message/ e-mail will be sent to scrutiny officer. </span></span></span></span></li>\n	</ol>\n	</li>\n</ol>\n\n<ol start=\"2\">\n	<li><span><span><span><strong><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Processing of the Application</span></span></span></strong></span></span></span>\n\n	<ol>\n		<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>The application would be scrutinized by the scrutiny officer and if any query raised by Scrutiny officer then the applicant would be required to address the query.</span></span></span></span></span></span></li>\n		<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Subsequently, if the application is found to be in order and all the attached documents is meeting requirements the application would move to Approval authority</span></span></span></span></span></span></li>\n	</ol>\n	</li>\n</ol>', '<p><span><span><span><strong><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Fresh Authorization</span></span></span></strong></span></span></span></p>\n\n<ol>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Land Documents/ Land Diversion/ Agreement Paper/ Parcha etc.</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>No Objection Certificate from neighbours and land owner.</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Site Plan of the unit.</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Detail project Report. </span></span></span></span></span></span></li>\n</ol>\n\n<ol>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Cost analysis data.</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Activates (Products &amp; By products manufacture).</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Waste generation (quantity of waste generation/stored).</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Environmental Management Plan.</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Details of pollution control systems such as Effluent Treatment Plant, scrubbers, etc. including mode of disposal of waste.</span></span></span></span></span></span></li>\n</ol>\n\n<p> </p>\n\n<p><span><span><span><strong><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Renewal of Authorization</span></span></span></strong></span></span></span></p>\n\n<ol>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Last year registration consent Certificate.</span></span></span></span></span></span></li>\n</ol>', '<p><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Authorization- 21 days</span></span></span></span></span></span></p>\n\n<p><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Renewal – 21 days<strong> </strong></span></span></span></span></span></span></p>'),
(20, '<a href=\"/node/39403\" hreflang=\"en\">Pollution - E Waste</a>', '', 0, '', 'Other Services', 'Tripura State Pollution Control Board', '<p><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Rs. 13,000/-</span></span></span></span></span></span></p>', 'Authorization under the E waste (Management &amp; Handling) Rules, 2011 ', '', 0, '<ol>\n	<li><span><span><span><strong><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Application</span></span></span></strong></span></span></span>\n	<ol>\n		<li><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>The Proponent shall submit Application on-line through the SWAAGAT portal. (swaagat.tripura.gov.in) </span></span></span></span></li>\n		<li><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>The applications must be filled as per instructions and submitted with the required documents. </span></span></span></span></li>\n		<li><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>When the application is filled up and submitted, a message/ e-mail will be sent to scrutiny officer. </span></span></span></span></li>\n	</ol>\n	</li>\n</ol>\n\n<ol start=\"2\">\n	<li><span><span><span><strong><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Processing of the Application</span></span></span></strong></span></span></span>\n\n	<ol>\n		<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>The application would be scrutinized by the scrutiny officer and if any query raised by Scrutiny officer then the applicant would be required to address the query.</span></span></span></span></span></span></li>\n		<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Subsequently, if the application is found to be in order and all the attached documents is meeting requirements the application would move to Approval authority</span></span></span></span></span></span></li>\n	</ol>\n	</li>\n</ol>', '<p><span><span><span><strong><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Fresh Authorization</span></span></span></strong></span></span></span></p>\n\n<ol>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Land Documents/ Land Diversion/ Agreement Paper/ Parcha etc.</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>No Objection Certificate from neighbours and land owner.</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Site Plan of the unit.</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Detail project Report. </span></span></span></span></span></span>\n	<ol>\n		<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Cost analysis data.</span></span></span></span></span></span></li>\n		<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Activates (Products &amp; By products manufacture).</span></span></span></span></span></span></li>\n		<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Waste generation (quantity of waste generation/stored).</span></span></span></span></span></span></li>\n		<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Environmental Management Plan.</span></span></span></span></span></span></li>\n		<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Details of pollution control systems such as Effluent Treatment Plant, scrubbers, etc. including mode of disposal of waste.</span></span></span></span></span></span></li>\n	</ol>\n	</li>\n</ol>\n\n<p><span><span><span><strong><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Renewal of Authorization</span></span></span></strong></span></span></span></p>\n\n<ol>\n	<li><span><span><span><strong><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Last year Authorization Certificate.</span></span></span></strong></span></span></span></li>\n</ol>', '<p><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Authorization- 21 days</span></span></span></span></span></span></p>\n\n<p><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Renewal – 21 days<strong> </strong></span></span></span></span></span></span></p>'),
(21, '<a href=\"/node/39402\" hreflang=\"en\">Pollution - Hazardous and Other Wastes</a>', '', 0, '<a href=\"/node/28382\" hreflang=\"en\">OTH-PD1</a>', 'Other Services', 'Tripura State Pollution Control Board', '<p><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Rs. 13,000/-</span></span></span></span></span></span></p>', 'Authorization under the Hazardous and Other Wastes (Management &amp; Transboundary Movement) Rules, 2016 ', '', 0, '<ol>\n	<li><span><span><span><strong><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Application</span></span></span></strong></span></span></span>\n	<ol>\n		<li><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>The Proponent shall submit Application on-line through the SWAAGAT portal. (swaagat.tripura.gov.in) </span></span></span></span></li>\n		<li><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>The applications must be filled as per instructions and submitted with the required documents. </span></span></span></span></li>\n		<li><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>When the application is filled up and submitted, a message/ e-mail will be sent to scrutiny officer. </span></span></span></span></li>\n	</ol>\n	</li>\n</ol>\n\n<ol start=\"2\">\n	<li><span><span><span><strong><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Processing of the Application</span></span></span></strong></span></span></span>\n\n	<ol>\n		<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>The application would be scrutinized by the scrutiny officer and if any query raised by Scrutiny officer then the applicant would be required to address the query.</span></span></span></span></span></span></li>\n		<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Subsequently, if the application is found to be in order and all the attached documents is meeting requirements the application would move to Approval authority</span></span></span></span></span></span></li>\n	</ol>\n	</li>\n</ol>', '<p><span><span><span><strong><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Fresh Authorization</span></span></span></strong></span></span></span></p>\n\n<ul>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Land Documents/ Land Diversion/ Agreement Paper/ Parcha etc.</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>No Objection Certificate from neighbours and land owner.</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Site Plan of the unit.</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Detail project Report. </span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Cost analysis data.</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Activates (Products &amp; By products manufacture).</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Waste generation (quantity of waste generation/stored).</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Emergency Response Plan (EPR).</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Environmental Management Plan.</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Details of pollution control systems such as Effluent Treatment Plant, scrubbers, etc. including mode of disposal of waste.</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Declaration to comply with all provisions including the scope of submitting bank guarantee in the event of spillage, leakage or fire while handling the hazardous and other waste.</span></span></span></span></span></span></li>\n</ul>\n\n<p><span><span><span><strong><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Renewal of Authorization</span></span></span></strong></span></span></span></p>\n\n<ul>\n	<li><span><span><span><strong><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Last year Authorization Certificate.</span></span></span></strong></span></span></span></li>\n</ul>', '<p><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Authorization- 21 days</span></span></span></span></span></span></p>\n\n<p><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Renewal – 21 days<strong> </strong></span></span></span></p>');
