(28, '<a href=\"/node/38216\" hreflang=\"en\">L04 - Boiler Registration</a>', '', 0, '<a href=\"/node/30085\" hreflang=\"en\">OTH-FB1</a>', 'Other Services', 'Boilers Organisation', '<p><strong>Flow Chart of Stagewise Details with Cost and Time: Registration of Boiler under the Boilers Act, 1923</strong></p>\n\n<table border=\"1\" class=\"MsoTableGrid\" style=\"margin-left:37px; border-collapse:collapse; border:1px solid\" width=\"100%\">\n	<tbody>\n		<tr>\n			<td style=\"border-bottom:1px solid black; width:35px; padding:0cm 7px 0cm 7px; border-top:1px solid black; border-right:1px solid black; border-left:1px solid black\" valign=\"top\">\n			<p align=\"center\" style=\"text-align:center\"><span style=\"font-size:11pt\"><b><span style=\"font-family:Times New Roman,serif\">Sl.</span></b></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:280px; padding:0cm 7px 0cm 7px; border-top:1px solid black; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p align=\"center\" style=\"text-align:center\"><span style=\"font-size:11pt\"><b><span style=\"font-family:Times New Roman,serif\">Stage</span></b></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:286px; padding:0cm 7px 0cm 7px; border-top:1px solid black; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p align=\"center\" style=\"text-align:center\"><span style=\"font-size:11pt\"><b><span style=\"font-family:Times New Roman,serif\">Timeline</span></b></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:286px; padding:0cm 7px 0cm 7px; border-top:1px solid black; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p align=\"center\" style=\"text-align:center\"><span style=\"font-size:11pt\"><b><span style=\"font-family:Times New Roman,serif\">Fees</span></b></span></p>\n			</td>\n		</tr>\n		<tr>\n			<td style=\"border-bottom:1px solid black; width:35px; padding:0cm 7px 0cm 7px; border-top:none; bor