px solid black; border-left:none\" valign=\"top\">\n			<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Times New Roman,serif\">30 days</span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:286px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Times New Roman,serif\">---</span></span></p>\n			</td>\n		</tr>\n		<tr>\n			<td style=\"border-bottom:1px solid black; width:35px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:1px solid black\" valign=\"top\">\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Times New Roman,serif\">3</span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:280px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Times New Roman,serif\">Total</span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:286px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Times New Roman,serif\">30 days</span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:286px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Times New Roman,serif\">---</span></span></p>\n			</td>\n		</tr>\n	</tbody>\n</table>\n\n<p align=\"center\" style=\"margin-left:30px; text-align:center\"> </p>\n\n<p align=\"center\" style=\"margin-left:30px; text-align:center\"> </p>\n\n<p align=\"center\" style=\"mar