top\">\n			<p><span style=\"font-size:11pt\"><span style=\"line-height:150%\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">For Boiler Rating not exceeding 10 sq. meters</span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:91px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p align=\"center\" style=\"text-align:center\"><span style=\"font-size:11pt\"><span style=\"line-height:150%\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">1800</span></span></span></p>\n			</td>\n		</tr>\n		<tr>\n			<td style=\"border-bottom:1px solid black; width:49px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:1px solid black\" valign=\"top\">\n			<p align=\"center\" style=\"text-align:center\"><span style=\"font-size:11pt\"><span style=\"line-height:150%\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">3</span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:498px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p><span style=\"font-size:11pt\"><span style=\"line-height:150%\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">For Boilers Rating exceeding 10 sq. meters but not exceeding 30 sq. meters </span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:91px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p align=\"center\" style=\"text-align:center\"><span style=\"font-size:11pt\"><span style=\"line-height:150%\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">2400</span></span></span></p>\n			</td>\n		</tr>\n		<tr>\n			<td style=\"border-bottom:1px solid black; width:49px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:1px solid black\" valign=\"top\">\n			<p align=\"center\" style=\"text-align:center\"><span style=\"font-size:11pt\"><span style=\"line-height:150%\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">4</span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:498px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p><span style=\"font-size:11pt\"><span style=\"line-height:150%\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">For Boilers Rating exceeding 30 sq. meters but not exceeding 50 sq. meters </span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:91px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p align=\"center\" style=\"text-align:center\"><span style=\"font-size:11pt\"><span style=\"line-height:150%\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">2700</span></span></span></p>\n			</td>\n		</tr>\n		<tr>\n			<td style=\"border-bottom:1px solid black; width:49px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:1px solid black\" valign=\"top\">\n			<p align=\"center\" style=\"text-align:center\"><span style=\"font-size:11pt\"><span style=\"line-height:150%\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">5</span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:498px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p><span style=\"font-size:11pt\"><span style=\"line-height:150%\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">For Boilers Rating exceeding 50 sq. meters but not exceeding 70 sq. meters </span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:91px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p align=\"center\" style=\