n style=\"font-size:11pt\"><span style=\"text-justify:inter-ideograph\"><span style=\"line-height:normal\"><span style=\"tab-stops:163.5pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">1.</span></span></span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:152px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"text-justify:inter-ideograph\"><span style=\"line-height:normal\"><span style=\"tab-stops:163.5pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Special Class</span></span></span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:138px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"text-justify:inter-ideograph\"><span style=\"line-height:normal\"><span style=\"tab-stops:163.5pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">15,000/-</span></span></span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:146px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p><span style=\"font-size:11pt\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">7,500/-</span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:144px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p><span style=\"font-size:11pt\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">5,000/-</span></span></span></p>\n			</td>\n		</tr>\n		<tr>\n			<td style=\"border-bottom:1px solid black; width:40px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:1px solid black\" valign=\"top\">\n			<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"text-justify:inter-ideograph\"><span style=\"line-height:normal\"><span style=\"tab-stops:163.5pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">2.</span></span></span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:152px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"text-justify:inter-ideograph\"><span style=\"line-height:normal\"><span style=\"tab-stops:163.5pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Class I</span></span></span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:138px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p><span style=\"font-size:11pt\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">10,000/-</span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:146px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p><span style=\"font-size:11pt\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">5,000/-</span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:144px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p><span style=\"font-size:11pt\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">4,000/-</span></span></span></p>\n			</td>\n		</tr>\n		<tr>\n			<td style=\"border-bottom:1px solid black; width:40px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:1px solid black\" valign=\"top\">\n			<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"text-justify:inter-ideograph\"><span style=\"line-height:normal\"><span style=\"tab-stops:163.5pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">3.</span></span></span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:152px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"text-justify:inter-ideograph\"><span style=\"line-height:normal\"><span style=\"tab-stops:163.5pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Class II</span></span></span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:138px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p><span style=\"font-size:11pt\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">5,000/-</span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:146px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p><span style=\"font-size:11pt\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">2,500/-</span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:144px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p><span style=\"font-size:11pt\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">2,000/-</span></span></span></p>\n			</td>\n		</tr>\n		<tr>\n			<td style=\"border-bottom:1px solid black; width:40px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:1px solid black\" valign=\"top\">\n			<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"text-justify:inter-ideograph\"><span style=\"line-height:normal\"><span style=\"tab-stops:163.5pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">4.</span></span></span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:152px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"text-justify:inter-ideograph\"><span style=\"line-height:normal\"><span style=\"tab-stops:163.5pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Class III</span></span></span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:138px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p><span style=\"font-size:11pt\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">2,500/-</span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:146px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p><span style=\"font-size:11pt\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">1,250/-</span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:144px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p><span style=\"font-size:11pt\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">1,000/-</span></span></span></p>\n			</td>\n		</tr>\n	</tbody>\n</table>\n\n<p style=\"margin-left:30px; margin-bottom:13px\"> </p>\n\n<p style=\"margin-bottom:8px\"> </p>\n\n<p style=\"margin-bottom:8px\"> </p>\n\n<p style=\"margin-bottom:8px\"><span style=\"font-size:11pt\"><span style=\"line-height:107%\"><span style=\"font-family:Calibri,sans-serif\"><b>G. <u>Risk category</u>: </b>All boilers are in high Risk category and documents needed as mentioned in 1(c).</span></span></span></p>\n\n<p> </p>\n\n<p><span style=\"font-size:11pt\"><span style=\"line-height:107%\"><span style=\"font-family:Calibri,sans-serif\"><b>H. <u>Size of Firm</u>: </b>All boilers and documents needed as mentioned in 1(c).</span></span></span></p>\n\n<p style=\"margin-left:30px; margin-bottom:13px\"> </p>\n\n<p style=\"margin-left:30px; margin-bottom:13px\"> </p>\n\n<p> </p>\n\n<p><strong>I. Business Location:</strong></p>\n\n<table border=\"1\" class=\"MsoTableGrid\" style=\"margin-left:37px; border-collapse:collapse; border:1px solid\" width=\"100%\">\n	<tbody>\n		<tr>\n			<td style=\"border-bottom:1px solid black; width:250px; padding:0cm 7px 0cm 7px; border-top:1px solid black; border-right:1px solid black; border-left:1px solid black\" valign=\"top\">\n			<p align=\"center\" style=\"text-align:center\"><span style=\"font-size:11pt\"><b><span style=\"font-family:Times New Roman,serif\">Business Location</span></b></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:250px; padding:0cm 7px 0cm 7px; border-top:1px solid black; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p align=\"center\" style=\"text-align:center\"><span style=\"font-size:11pt\"><b><span style=\"font-family:Times New Roman,serif\">Industrial Estate</span></b></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:250px; padding:0cm 7px 0cm 7px; border-top:1px solid black; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p align=\"center\" style=\"text-align:center\"><span style=\"font-size:11pt\"><b><span style=\"font-family:Times New Roman,serif\">Urban</span></b></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:250px; padding:0cm 7px 0cm 7px; border-top:1px solid black; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p align=\"center\" style=\"text-align:center\"><span style=\"font-size:11pt\"><b><span style=\"font-family:Times New Roman,serif\">Rural</span></b></span></p>\n			</td>\n		</tr>\n		<tr>\n			<td style=\"border-bottom:1px solid black; width:250px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:1px solid black\" valign=\"top\">\n			<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Times New Roman,serif\">Documents to be submitted with the Application as per Sl. No.1(C)</span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:250px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Times New Roman,serif\">Applicable for all Business Locations</span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:250px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Times New Roman,serif\">Applicable for all Business Locations</span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:250px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Times New Roman,serif\">Applicable for all Business Locations</span></span></p>\n			</td>\n		</tr>\n	</tbody>\n</table>\n\n<p> </p>\n\n<p><strong>J. Investor:</strong></p>\n\n<table border=\"1\" class=\"MsoTableGrid\" style=\"margin-left:37px; border-collapse:collapse; border:1px solid\" width=\"100%\">\n	<tbody>\n		<tr>\n			<td style=\"border-bottom:1px solid black; width:250px; padding:0cm 7px 0cm 7px; border-top:1px solid black; border-right:1px solid black; border-left:1px solid black\" valign=\"top\">\n			<p align=\"center\" style=\"text-align:center\"><span style=\"font-size:11pt\"><b><span style=\"font-family:Times New Roman,serif\">Investor</span></b></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:250px; padding:0cm 7px 0cm 7px; border-top:1px solid black; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p align=\"center\" style=\"text-align:center\"><span style=\"font-size:11pt\"><b><span style=\"font-family:Times New Roman,serif\">Domestic Investor</span></b></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:250px; padding:0cm 7px 0cm 7px; border-top:1px solid black; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p align=\"center\" style=\"text-align:center\"><span style=\"font-size:11pt\"><b><span style=\"font-family:Times New Roman,serif\">Foreign Investor</span></b></span></p>\n			</td>\n		</tr>\n		<tr>\n			<td style=\"border-bottom:1px solid black; width:250px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:1px solid black\" valign=\"top\">\n			<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Times New Roman,serif\">Documents to be submitted with the Application as per Sl. No.1(C)</span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:250px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Times New Roman,serif\">Documents as per Sl. No.1(C)</span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:250px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Times New Roman,serif\">Documents as per Sl. No.1(C) and permission from the authority of Govt. of India</span></span></p>\n			</td>\n		</tr>\n	</tbody>\n</table>\n', 'Application for Registration of Boilers under the Boilers Act, 1923', '', 0, '<p><strong>Submission of Application: </strong></p>\n\n<ul>\n	<li>The Entrepreneur shall submit application on-line through <strong>SWAAGAT </strong>(<a href=\"https://swaagat.tripura.gov.in\">https://swaagat.tripura.gov.in</a>).</li>\n	<li>The online application, to be verified whether all required documents are attached with fee details.</li>\n	<li>The deficiencies, if any, in the application, shall be informed to the applicant.</li>\n</ul>\n\n<p><strong>Processing of the Application: </strong></p>\n\n<ul>\n	<li>If the application is found to be in order, the department will allocate an inspector to conduct an Inspection.</li>\n	<li>Inspector will follow the procedure as mentioned below:</li>\n</ul>\n\n<ul>\n	<li>Ground inspection and Simulation test of pressure parts.</li>\n	<li>Boilers drum alignment inspection.</li>\n	<li>Tack welding inspection before final welding. </li>\n	<li>Welded joints inspection and marking for Radiography. </li>\n	<li>After satisfactory erection, Hydraulic Test of boiler.</li>\n	<li>Provisional Order (Form-V) will be issued after successful Hydraulic Test.</li>\n	<li>Steam Test as per Regulation.</li>\n</ul>\n\n<ul>\n	<li>The inspector then uploads the inspection report to the Department.</li>\n	<li>Based on the report, if all are in order, Chief Inspector of Factories &amp; Boilers will sign and upload the approval in SWAAGAT portal.</li>\n</ul>\n\n<ul>\n	<li>Counter signed of Provisional Order (Form-V) issued by the Inspector.</li>\n	<li>Registration number will be allotted after successful Steam Test.</li>\n	<li><em>Engraving</em> of registry <em>number</em>.</li>\n	<li>Final Operation certificate (Form-VI) will be issued for 12 months from the date of hydraulic test.</li>\n</ul>\n\n<p>The entrepreneur can view and download the digital copy of the approval in his login.</p>', '<ul>\n	<li>Folder with Form-II, III, IIIA &amp; drawings, etc.</li>\n	<li>Form-B No.-1.</li>\n	<li>Welding Procedure Specification (<strong>WPS</strong>) for approval.</li>\n	<li>Details of Erectors and Approval:\n	<ul>\n		<li>List of tools and tackles.</li>\n		<li>List of technical personnel detailing designation, educational qualifications and relevant experience (attach copies of documents/Certificates).</li>\n		<li> List of welders (attach copies of valid Certificates).</li>\n		<li>Citizenship Certificate or Permanent Resident Certificate.</li>\n		<li>PAN card.</li>\n		<li>Aadhaar card.</li>\n		<li>Passport size photograph with signature</li>\n	</ul>\n	</li>\n</ul>', '<p>Boiler Registration: 30 days</p>');
INSERT INTO `information_wizards` (`id`, `title`, `field_fee_structure_files`, `delta`, `field_noc_master_link`, `field_wizard_category`, `field_wizard_department`, `field_wizard_fee_text`, `field_wizard_noc_name`, `field_wizard_notification`, `delta_1`, `field_wizard_process`, `field_wizard_required_documents`, `field_wizard_timeline`) VALUES
(29, '<a href=\"/node/38223\" hreflang=\"en\">C1-Cooperative</a>', '', 0, '', 'Special Services', 'Department of Co-operation', '<p><span><span><span>No fees is required for registration of Co-op Societies.</span></span></span></p>', 'Registration of Co-op Societies', '', 0, '<p><span><span><span><span><span><span><span><span>a) The Proponent shall submit Application on-line through the EoDB portal: </span></span></span></span><span><a href=\"https://swaagat.tripura.gov.in\"><span><span><span>https://swaagat.tripura.gov.in</span></span></span></a></span>  </span></span></span></span></p>\n\n<p><span><span><span><span><span><span><span><span>b) The applications must be filled as per instructions and submitted with the required documents</span></span></span></span></span></span></span></span></p>', '<ol>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Minute copy of the first organisation meeting.</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Prescribed Bye-laws 5(five) Copies.</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Co-operative Special Form No -1.</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Co-operative Special Form No -7.</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Cash Account.</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>3 (three) years project report, i.e scheme which would be related with objects of the concerned Proposed Society.</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Bank Deposit Slip with Certificate of Bank Manager.</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>List of Promoter members.</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Share Schedule.</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span> Different family members Certificate.</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Voter Identity Card for proof of identity of the promoter members.</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span> Other papers like Land documents, NOC of premises owner or Agreement of using premises.</span></span></span></span></span></span></li>\n</ol>', '<p>30 days</p>'),
(30, '<a href=\"/node/39413\" hreflang=\"en\">Drug - Special - Retail &amp; Wholesale</a>', '', 0, '<a href=\"/node/37462\" hreflang=\"en\">SPC-DC1</a>', 'Special Services', 'Drugs Control Administration', '<p> </p>\n\n<p> </p>\n\n<p><strong>Retail</strong></p>\n\n<ol>\n	<li>Retail Licence- Rs. 3000.00</li>\n	<li>Retails (restricted) licence - Rs. 1000.00</li>\n</ol>\n\n<p><strong>Wholesale</strong></p>\n\n<ol>\n	<li>Wholesale Licence - Rs. 3000.00</li>\n</ol>\n\n<p>+ Motor Vehicle Licence - Rs. 3000.00 (if added)</p>', 'Retail &amp; Wholesale Licence', '', 0, '<p><span><span><span><span><strong><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Submission of Application:</span></strong></span></span></span></span></p>\n\n<ol>\n	<li><span><span><span><span><span>The Applicant/ Entrepreneur shall submit application in respective license types of drugs  they  wish to sell,  through online mode in SWAAGAT portal (</span><a href=\"https://swaagat.tripura.gov.in\"><span>https://swaagat.tripura.gov.in</span></a><span>)</span></span></span></span></span></li>\n	<li><span><span><span><span><span>The application is pre-scrutinized online at SWAAGAT to verify that the application is in full form with all required enclosures. </span></span></span></span></span></li>\n	<li><span><span><span><span><span>The deficiencies, if any, in the application will be informed by the scrutinizing officers to the applicant.</span></span></span></span></span></li>\n</ol>\n\n<p><span><span><span><span><strong><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Processing of the Application:</span></strong></span></span></span></span></p>\n\n<ol>\n	<li><span><span><span><span><span>If the application is found to be in order, the department will allocate an inspector to conduct an inspection of the premises for which the license may be granted. </span></span></span></span></span></li>\n	<li><span><span><span><span><span>The  Inspection Report will be uploaded by the Inspector to the Department.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Based on the report, if all are in order, Deputy Drugs Controller &amp; Licensing Authority, (State Licensing Authority) will sign and upload the approval in SWAAGAT portal.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>The entrepreneur can view and download the license copy in his login.</span></span></span></span></span></li>\n</ol>', '<ol>\n	<li><span><span><span><span><span>Trade Licence </span></span></span></span></span></li>\n	<li><span><span><span><span><span>Rental Agreement of the premises where the business is to be carried.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Invoice of the Refrigerator for storage of freezing items.(optional)</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Undertaking of Registration</span></span></span></span></span></li>\n	<li><span><span><span><span><strong><span>Pharmacist : Pharmacist Registration Certificate, Aadhaar .(For Retail)</span></strong></span></span></span></span></li>\n	<li><span><span><span><span><strong><span>Competent Person: Aadhaar, Experience Certificate &amp; Qualification. (For Wholesale), NOC/ Release order of previous engagement.</span></strong></span></span></span></span></li>\n	<li><span><span><span><span><strong><span>Motor Vehicle :  </span></strong><span>Motor Vehicle Registration, Road Tax Certificate &amp; PUC</span></span></span></span></span></li>\n</ol>\n\n<p> </p>\n\n<p><strong><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Documents related to Applicant:</span></span></span></span></span></strong></p>\n\n<p><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">i)        In case of partnership- Valid partner deed &amp; List of partners.</span></span></span></span></span></p>\n\n<ol>\n	<li><span><span><span><span><span>In case of public or private limited company- Articles of Association, List of Directors, certificate of incorporation of the company, Resolution of Board of Directors etc.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>In case of private company- List of shareholders.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>In case of factory owned by the Central or State govt. undertaking-Govt. order for having appointed the Occupier.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>In case of Co-op Society- Registered document, Resolution of Board, list of shareholders, President/ Secretary.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Citizenship Certificate or Permanent Resident Certificate or AADHAAR.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>PAN Card</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Passport size photograph with signature.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>NOCs, if applicable, etc.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Income Tax/ Professional Tax Clearance Certificate</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Such other particulars as the Licensing Authority may require.</span></span></span></span></span></li>\n</ol>', '<p><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\">Sale License (retail/wholesale) : 30 days.</span></span></span></span> </span></p>\n\n<div class=\"flow-chart\">\n<h5> </h5>\n\n<h5> </h5>\n\n<h5>Flow Chart of Stagewise Details with Cost and Time:</h5>\n\n<h6>Retail &amp; Wholesale</h6>\n\n<table border=\"1\" class=\"MsoTableGrid\" width=\"100%\">\n	<thead>\n		<tr>\n			<th>Sl no.</th>\n			<th>Stage</th>\n			<th>Timeline</th>\n			<th>Fees</th>\n		</tr>\n	</thead>\n	<tbody>\n		<tr>\n			<td>1</td>\n			<td>Application submission by applicant</td>\n			<td>0 days</td>\n			<td>Rs. 3000/-</td>\n		</tr>\n		<tr>\n			<td>2</td>\n			<td>Inspecting Officer (Drugs)/ Reviewing Officer Check documents &amp; Inspection of the premises as per requirements of D&amp;C Act</td>\n			<td>10 days</td>\n			<td>0</td>\n		</tr>\n		<tr>\n			<td>3</td>\n			<td>Licensing Authority verify the documents again &amp; NOC Issued</td>\n			<td>20 days</td>\n			<td>0</td>\n		</tr>\n		<tr>\n			<td class=\"total\" colspan=\"2\">Total</td>\n			<td>30 days</td>\n			<td>Rs. 3000/-</td>\n		</tr>\n	</tbody>\n</table>\n</div>\n');
