 black; border-left:none\" valign=\"top\">\n			<p align=\"center\" style=\"text-align:center\"> </p>\n			</td>\n		</tr>\n		<tr>\n			<td style=\"border-bottom:1px solid black; width:66px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:1px solid black\" valign=\"top\">\n			<p align=\"center\" style=\"text-align:center\"><span style=\"font-size:11pt\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"font-family:&quot;Tahoma&quot;,sans-serif\">10</span></span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:94px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p align=\"center\" style=\"text-align:center\"> </p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:332px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<ol style=\"list-style-type:lower-alpha\">\n				<li style=\"margin-left:8px\"><span style=\"font-size:11pt\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"font-family:&quot;Tahoma&quot;,sans-serif\">On site manufacturing  Class A or Class B medical device; or</span></span></span></span></li>\n			</ol>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:179px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p align=\"center\" style=\"text-align:center\"><span style=\"font-size:11pt\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"font-family:&quot;Tahoma&quot;,sans-serif\">5000</span></span></span></span></p>\n			</td>\n		</tr>\n		<tr>\n			<td style=\"border-bottom:1px solid black; width:66px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:1px solid black\" valign=\"top\">\n			<p align=\"center\" style=\"text-align:center\"><span style=\"font-size:11pt\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"font-family:&quot;Tahoma&quot;,sans-serif\">11</span></span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:94px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p align=\"center\" style=\"text-align:center\"> </p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:332px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<ol start=\"2\" style=\"list-style-type:lower-alpha\">\n				<li style=\"margin-left:8px\"><span style=\"font-size:11pt\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"font-family:&quot;Tahoma&quot;,sans-serif\">On site manufacturing  Class C or Class D medical device; or</span></span></span></span></li>\n			</ol>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:179px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p align=\"center\" style=\"text-align:center\"><span style=\"font-size:11pt\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"font-family:&quot;Tahoma&quot;,sans-serif\">50000</span></span></span></span></p>\n			</td>\n		</tr>\n		<tr>\n			<td style=\"border-bottom:1px solid black; width:66px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:1px solid black\" valign=\"top\">\n			<p align=\"center\" style=\"text-align:center\"><span style=\"font-size:11pt\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"font-family:&quot;Tahoma&quot;,sans-serif\">12</span></span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:94px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p align=\"center\" style=\"text-align:center\"> </p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:332px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<ol start=\"3\" style=\"list-style-type:lower-alpha\">\n				<li style=\"margin-left:8px\"><span style=\"font-size:11pt\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"font-family:&quot;Tahoma&quot;,sans-serif\">each distinct medical device of Class A or Class B; or</span></span></span></span></li>\n			</ol>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:179px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p align=\"center\" style=\"text-align:center\"><span style=\"font-size:11pt\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"font-family:&quot;Tahoma&quot;,sans-serif\">500</span></span></span></span></p>\n			</td>\n		</tr>\n		<tr>\n			<td style=\"border-bottom:1px solid black; width:66px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:1px solid black\" valign=\"top\">\n			<p align=\"center\" style=\"text-align:center\"><span style=\"font-size:11pt\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"font-family:&quot;Tahoma&quot;,sans-serif\">13</span></span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:94px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p align=\"center\" style=\"text-align:center\"> </p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:332px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<ol start=\"4\" style=\"list-style-type:lower-alpha\">\n				<li style=\"margin-left:8px\"><span style=\"font-size:11pt\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"font-family:&quot;Tahoma&quot;,sans-serif\">each distinct medical device of Class C or Class D; or</span></span></span></span></li>\n			</ol>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:179px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p align=\"center\" style=\"text-align:center\"><span style=\"font-size:11pt\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"font-family:&quot;Tahoma&quot;,sans-serif\">1000</span></span></span></span></p>\n			</td>\n		</tr>\n	</tbody>\n</table>\n\n<p align=\"center\" style=\"text-align:center\"> </p>\n\n<p> </p>\n\n<p> </p>\n\n<p> </p>\n', 'Application for Retention of Manufacturing Licence', '', 0, '<p><strong><span><span><span><span><span>Submission of Application</span></span></span></span></span></strong></p>\n\n<ul>\n	<li><span><span><span><span><span>The Entrepreneur shall submit application online through SWAGAAT portal (</span><a href=\"https://swaagat.tripura.gov.in\"><span>https://swaagat.tripura.gov.in</span></a><span>)</span></span></span></span></span></li>\n</ul>\n\n<ul>\n	<li><span><span><span><span><span>If the data matched with the previous data system will allow for processing the submission of auto-renewal on deposition of fees and entrepreneur can view and down load the retention of license receipt with valid period for the next 5 (five) years.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Auto Renewal is not accessible if any violations observed in any particular manufacturing unit.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>If the data is not matched with previous data then the application is pre-scrutinized online at SWAGAAT to verify that the applicant is in full form with all required enclosures.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>The deficiencies, if any, in the application will be informed by the scrutinizing officers to the application.</span></span></span></span></span></li>\n</ul>\n\n<p><span><span><span><span><strong><span>Processing of the Application</span></strong></span></span></span></span></p>\n\n<ul>\n	<li><span><span><span><span><span>A licence issued shall remain valid if licensee deposits a licence retention fee referred to in sub-rule (2) before the expiry of a period of every succeeding five years from the date of its issue, unless, it is suspended or cancelled by the licensing authority.</span></span></span></span></span></li>\n</ul>', '', '<p><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Auto renewal (Retention of Licence)</span></span></span></span></span></p>');
INSERT INTO `information_wizards` (`id`, `title`, `field_fee_structure_files`, `delta`, `field_noc_master_link`, `field_wizard_category`, `field_wizard_department`, `field_wizard_fee_text`, `field_wizard_noc_name`, `field_wizard_notification`, `delta_1`, `field_wizard_process`, `field_wizard_required_documents`, `field_wizard_timeline`) VALUES
(32, '<a href=\"/node/39411\" hreflang=\"en\">Drug - CFE - Manufacturing</a>', '', 0, '', 'Consent for Establishment', 'Drugs Control Administration', '', 'Application for the grant of or renewal of a licence to manufacture for sale and distribution', '', 0, '<p><span><span><span><span><strong><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Submission of Application:</span></strong></span></span></span></span></p>\n\n<ol>\n	<li><span><span><span><span><span>The Applicant/ Entrepreneur shall submit application in respective license types of drugs  they  which to manufacture through online mode in SWAAGAT portal (</span><a href=\"https://swaagat.tripura.gov.in\"><span>https://swaagat.tripura.gov.in</span></a><span>)</span></span></span></span></span></li>\n	<li><span><span><span><span><span>The application is pre-scrutinized online at SWAAGAT to verify that the application is in full form with all required enclosures. </span></span></span></span></span></li>\n	<li><span><span><span><span><span>The deficiencies, if any, in the application will be informed by the scrutinizing officers to the applicant.</span></span></span></span></span></li>\n</ol>\n\n<p><span><span><span><span><strong><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Processing of the Application:</span></strong></span></span></span></span></p>\n\n<ol>\n	<li><span><span><span><span><span>If the application is found to be in order, the department will allocate an inspector to conduct an Inspection and for the license which required Central License Approving Authority (CLAA), Drugs Control General (India) (DCG(I), New Delhi the application and letter will issued by State Licensing Authority to depute an Inspector from CDSCO office for joint inspection.</span></span></span></span></span><span><span><span><span> </span></span></span></span></li>\n	<li><span><span><span><span><span>The Joint Inspection Report will be uploaded by the Inspector to the Department.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Based on the report, if all are in order, Deputy Drugs Controller &amp; Licensing Authority, (State Licensing Authority)  will sign and upload the approval in SWAAGAT portal. (If the license is requires the approval of Central License Approving Authority (CLAA) for sign upon receiving the said License sign by CLAA and the same will be uploaded in SWAGAAT portal.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>The entrepreneur can view and download the license copy in his login.</span></span></span></span></span></li>\n</ol>', '<ol>\n	<li><span><span><span><span><span>Plan drawing of manufacturing unit/ factory details as per requirement of manufacturing.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Detailed building plan</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Process Flow chart and write up.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>List of Machinery of Equipments along with capacity and other specification to be used in manufacturing.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>List of Instruments, Chemicals etc with their specifications which will be used for testing.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Standard Operating Procedure (SOP)</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Land document- Sale deed/ lease deed/ rental agreement.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>List of products with proper name, trade name (If any),composition, colour, strength and other excipients used and pack size.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Method of Analysis of the products proposed to manufactured</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Draft Labels of all the drugs to be manufactured. </span></span></span></span></span></li>\n	<li><span><span><span><span><span>Name of technical staff with qualification and experience (Manufacturing &amp; Testing) with supportive document.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Trade Licence</span></span></span></span></span></li>\n	<li><span><span><span><span><span>NOC from State Pollution Control Board</span></span></span></span></span></li>\n	<li><span><span><span><span><span>NOC from Chief Inspector of Factories &amp; Boilers</span></span></span></span></span></li>\n	<li><span><span><span><span><span>List of standard/ reference Books.</span></span></span></span></span></li>\n</ol>\n\n<p><strong><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Documents related to Occupier:</span></span></span></span></span></strong></p>\n\n<ol>\n	<li><span><span><span><span><span>In case of partnership- Valid partner deed &amp; List of partners.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>In case of public or private limited company- Articles of Association, List of Directors, certificate of incorporation of the company, Resolution of Board of Directors etc.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>In case of private company- List of shareholders.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>In case of factory owned by the Central or State govt. undertaking-Govt. order for having appointed the Occupier.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Incase of Co-op Society- Registered document, Resolution of Board, list of shareholders, President/ Secretary.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Citizenship Certificate or Permanent Resident Certificate or AADHAAR.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>PAN Card</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Passport size photograph with signature.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Land diversion certificate from competent authority, if applicable.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>NOCs, if applicable, etc.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Previously approved plans and Reference Number of the Factory in case of additional construction or installation of machinery.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Income Tax Clearance Certificate</span></span></span></span></span></li>\n	<li><span><span><span><span><span>Such other particulars as the Licensing Authority may require.</span></span></span></span></span></li>\n</ol>', '<p><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Manufacturing License: 30 days.</span></span></span></span></span></p>'),
(33, '<a href=\"/node/38227\" hreflang=\"en\">EI-Clearance Certificate -CFO</a>', '', 0, '<a href=\"/node/19142\" hreflang=\"en\">CFO-EI1</a>', 'Consent for Operation', 'Electrical Inspectorate', '<p><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Fees for inspection of electrical gadgets is against estimation</span></span></span></p>', 'Electrical Clearance Certificate from Department of Electrical Inspectorate', '', 0, '<ul>\n	<li><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span><span>Application for Electrical Clearance Certificate:</span></span></span></span></span></span></li>\n</ul>\n\n<ol>\n	<li><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>The Proponent shall submit application on-line through the online single window portal (www.swaagat.tripura.gov.in)</span></span></span></span></span></li>\n	<li><span><span><span><span><span>The applications are then sent to Department for scrutiny.</span></span></span></span></span></li>\n</ol>\n\n<ul>\n	<li><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span><span>Processing of the Application:</span></span></span></span></span></span></li>\n</ul>\n\n<ol>\n	<li><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span><span>Once the documents are uploaded, scrutiny of the application forms with documents are carried out. Based on the scrutiny the department can raise query which will be visible on the dashboard.</span></span></span></span></span></span></li>\n	<li><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span><span> Once the query is resolved, department will raise the amount through issue of challan as inspection fee of electrical gadgets that are installed and not charged for payment for electrical clearance.</span></span></span></span></span></span></li>\n	<li><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span><span> Once payment is made, the applicant will receive the acknowledgement for payment.</span></span></span></span></span></span></li>\n	<li><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span><span>On receiving the payment, inspection will be scheduled for the site.</span></span></span></span></span></span></li>\n	<li><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span><span>After completion of inspection, Form of order will be uploaded on the applicant’s dashboard. The applicant has to respond to the defects, if any raised by the department. Once the defects has been resolved, the applicant has to submit the compliance report.</span></span></span></span></span></span></li>\n	<li><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span><span>The department will review the compliance report and if required raise query, once the query is resolved the department will issue the electrical clearance certificate for charging the electrical gadgets. The certificate will be available in the dashboard.</span></span></span></span></span></span></li>\n</ol>', '<ol>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Duly filled in” Form of Inspection Report” {As per Provision in CEA (Measures Relating to Safety and Electric Supply) Regulation, 2010.</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Single line diagram of electrical installation should be enclosed.</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Manufacturing test result of each and every equipment should be enclosed.</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Name and license copy of Supervisor license holder (preferable Degree/ Diploma Engineer) person who is regularly engaged for time to time observation of all the electrical equipment of this building.</span></span></span></span></span></span></li>\n</ol>', '<p><span><span>15(Fifteen) days</span></span></p>'),
(34, '<a href=\"/node/38226\" hreflang=\"en\">EI-Building Plan-CFE</a>', '', 0, '<a href=\"/node/13649\" hreflang=\"en\">CFE-EI1</a>', 'Consent for Establishment', 'Electrical Inspectorate', '<p><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Fees for inspection of the site of the building is Rs. 100 per floor of the building.</span></span></span></span></span></p>', 'Application for Building Plan', '', 0, '<ul>\n	<li><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Application for Building Plan:</span></span></span></span></span></li>\n</ul>\n\n<ol>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>The Proponent shall submit application on-line through the online single window portal (</span></span></span><a href=\"http://www.swaagat.tripura.gov.in\"><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>www.swaagat.tripura.gov.in</span></span></a><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>).</span></span></span></span></span></span></li>\n	<li><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>The applications are then sent to Department for scrutiny.</span></span></span></span></span></span></li>\n</ol>\n\n<ul>\n	<li><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Processing of the Application:</span></span></span></span></span></li>\n</ul>\n\n<p><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>(a) Scrutiny of the application forms are carried out and if there is any query it will be visible on the dashboard.</span></span></span></span></span></p>\n\n<p><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span> (b)  Post query resolution, department will raise the amount through issue of challan as  inspection fee for payment for approval of building plan.</span></span></span></span></span></p>\n\n<p><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>(c)Once the payment is made, the applicant will receive the acknowledgement for payment.</span></span></span></span></span></p>\n\n<p><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>(d)If any further query is raised by department it will be visible on the dashboard.</span></span></span></span></span></p>\n\n<p><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>(e) In case no query is raised or query is resolved department will issue an approval  or conditional approval after inspection of the building site and it will be available on the dash board.</span></span></span></span></span></p>', '<ol>\n	<li><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>The structural layout showing plan and elevations with sectional and safe clearances.</span></span></span></span></span></li>\n	<li><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Mutation of the land where building is to be constructed.</span></span></span></span></span></li>\n	<li><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Tax clearance certificate of the land where building is to be constructed.</span></span></span></span></span></li>\n</ol>', '<p><span><span>07(Seven) days</span></span></p>'),
(35, '<a href=\"/node/38232\" hreflang=\"en\">Excise-Foreign-Liquor</a>', '', 0, '<a href=\"/node/13645\" hreflang=\"en\">CFE-EXD1</a>', 'Consent for Operation', 'Excise', '<ul>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">License Fee - Rs.5,00,000/- (Rupees Five Lakhs) only per annum.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Renewal Fee - Rs.5,00,000/- (Rupees Five Lakhs) only per annum.</span></span></span></span></span></li>\n</ul>', 'Application for License for setting up Foreign Liquor Bottling Unit', '', 0, '<ul>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Applicant </span><span>shall apply </span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">through online (</span><a href=\"http://www.swaagat.tripura.gov.in\"><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">www.swaagat.tripura.gov.in</span></a><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">) portal </span><span>to the Excise Commissioner through the Collector of Excise (DM &amp; Collector) </span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">along with required documents.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">The deficiencies in the application will be informed to the applicant.</span></span></span></span></span></li>\n</ul>\n\n<p><span><span><span><span><strong><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Processing of the Application:</span></strong></span></span></span></span></p>\n\n<ul>\n	<li><span><span><span><span><span>On receipt of the application, and after consulting the Collector regarding the suitability of the site, and buildings, if there by any already and on any other points and on receipt of the Collector’s opinion and after such further inquiry as he deems necessary, the Excise Commissioner shall decide whether the license for the opening of the distillery should be granted or not. The number of distilleries which can be allowed to be opened in Tripura mainly for the supply of country spirit, is limited and in deciding whether a license for the working of a distillery is to be granted or not, the Excise Commissioner will take into full consideration the purpose for which it is purposed to open the distillery and the demand or necessity for such a distillery</span><span>.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>If the Excise Commissioner sanctions the opening of a distillery, he shall so inform the applicant and the Collector of Excise.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>The applicant shall then be called upon to make arrangements for the construction of the distillery. Upon completion of the building and after the stills and other appliances and apparatus have been set up, he must deposit two fresh copies of the plans with the Collector, who shall cause them to be verified in any manner be thinks proper, and then submit one copy to the Excise Commissioner for examination and for comparison with the plans first submitted, and for any further verification he may think necessary. After final approval by the Excise Commissioner, the Collector will be instructed to grant a license to the applicant in the prescribed form. The applicant shall be bound to conform to the wishes of the Excise Commissioner within a reasonable time to be fixed by the officer regarding any addition or alteration to the buildings, stills, vats or other permanent apparatus or plant which he considers necessary, whether before or after the final plans are submitted for the proper security of the revenue or to render illicit practices impracticable.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>No addition or alteration to the buildings, stills or other permanent apparatus as shown in the plans finally submitted by the applicant shall be made without the previous sanction of the Excise Commissioner obtained through the officer-in-charge and the Collector. If the Excise Commissioner so directs, such additions or alterations may be permitted by the collector subject to the Excise Commissioner’s approval. When any such additions or alterations are made fresh plans must be submitted to the Excise Commissioner through the Collector with a certificate from the Officer-in-charge that they are correct.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>It will be open to the Excise Commissioner to verify at any time any of the descriptions and plans above mentioned, and on proof of error, to require fresh ones to be submitted for sanction. Such verification may be made by any officer deputed for the purpose, and such officer shall be allowed full access to the premises. Sanction to the plants may be withheld until any point in respect of which they differ from plans already sanctioned has been rectified to the satisfaction of the Excise Commissioner. The distiller shall be bound to carry out such rectification within a reasonable time to be fixed by the Excise Commissioner.</span></span></span></span></span></li>\n	<li><span><span><span><span><span><span>Before the license to work the distillery is granted by the Collector, the distiller shall give a security of Rs. 50,000.00 in cash or Government Promissory Notes for the due observance of the conditions of the license :</span></span></span></span></span></span><span><span><span><span><span> </span></span></span></span></span></li>\n</ul>\n\n<p><span><span><span><span><span><span>     Provided that in the case of a distiller who is required to pay the fee under the proviso to Rule 55, the amount of security   shall be Rs. 1,000/-or such other higher sum as may be fixed by the Excise Commissioner.</span></span></span></span></span></span></p>\n\n<ul>\n	<li><span><span><span><span><span><span>The distiller shall also execute a bond in the prescribed form pledging the distillery premises, stills, all apparatus and utensils employed in the manufacture of spirit and the stock-in-trade for the due discharge of all payments which may become due to the Government: </span></span></span></span></span></span></li>\n</ul>\n\n<p><span><span><span><span><span><span>     Provided that in lieu of so pledging the distillery premises the distiller may deposit Government Promissory Notes of such value as the Excise Commissioner may direct, and execute an indemnity bond of a value fixed by the Excise Commissioner.</span></span></span></span></span></span></p>\n\n<ul>\n	<li><span><span><span><span><span><span>The license for a distillery must be renewed annually. Such renewal will be granted by the Collector subject to the approval of the Excise Commissioner.</span></span></span></span></span></span></li>\n</ul>', '<ul>\n	<li><span><span><span><span><span>The name or names, and the address or addresses, of the person or persons applying.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>The purpose for which the distillery is proposed to be opened, specifying in detail the nature of the business which the applicant desires to carry on therein.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>The name of the place in which, the site on which and the building in which the distillery is to be constructed or worked.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>The number and full description of the stills, vats and other permanent apparatus which the applicant wishes to work or set up and the size and capacity of such stills, etc.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>The date from which, in the event of a license being granted to him, the applicant proposes to commence working the distillery.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>The amount of security which the applicant is ready to furnish for the due performance of the conditions on which a license may be granted to him.</span></span></span></span></span></li>\n	<li><span><span><span><span><span>A correct plan of the building which he intends to use or to construct for his distillery, and a plan showing the position of stills, vats and other permanent apparatus therein, and a list of store-rooms, warehouse, etc. connected therewith.</span><strong> </strong></span></span></span></span></li>\n</ul>', '<ul>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Issuance of LoI – 25 (Twenty Five) days (CFE). </span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Approval for License - 25 (Twenty Five) days (CFO).</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Issuance of License – 05 (Five) days (CFO).</span></span></span></span></span></li>\n</ul>'),
(36, '<a href=\"/node/38231\" hreflang=\"en\">Excise-Country-Liquor</a>', '', 0, '<a href=\"/node/13645\" hreflang=\"en\">CFE-EXD1</a>', 'Consent for Operation', 'Excise', '<ul>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">License Fee - Rs.5,00,000/- (Rupees Five Lakhs) only per annum.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Renewal Fee - Rs.5,00,000/- (Rupees Five Lakhs) only per annum.</span></span></span></span></span></li>\n</ul>', 'Application for License for setting up Country Liquor Bottling Unit', '', 0, '<ul>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Applicant shall apply through online (</span><a href=\"http://www.swaagat.tripura.gov.in\"><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">www.swaagat.tripura.gov.in</span></a><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">) portal only to the Excise Commissioner along with required documents.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">The deficiencies in the application will be informed to the applicant.</span></span></span></span></span></li>\n</ul>\n\n<p><span><span><span><span><strong><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Processing of the Application:</span></strong></span></span></span></span></p>\n\n<ul>\n	<li><span><span><span><span><span>On receipt of the application, the Excise Commissioner shall verify or inquire the suitability of the site, and buildings, if thereby any already and on any other points as he deems necessary and decide whether the license for the opening of the Country liquor bottling unit should be granted or not taking into full consideration the purpose for which it is proposed to open the Country liquor bottling unit and the demand or necessity for such a Country liquor bottling unit.</span></span></span></span></span></li>\n	<li><span><span><span><span><span><span>The Excise Commissioner shall inform the applicant through Letter of Intent (LoI) regarding the sanction of the opening of Country liquor bottling unit.</span></span></span></span></span></span></li>\n	<li><span><span><span><span><span><span>The applicant shall then be called upon to make arrangements for the construction of the Country liquor bottling unit. Upon completion of the building and after the stills and other appliances and apparatus have been set up, he must deposit two fresh copies of the plans with the Excise Commissioner, who shall cause them to be verified in any manner be thinks proper and for comparison with the plans first submitted. The applicant shall be required to obtain necessary clearance from relevant Departments regarding the setting up of the Country liquor bottling unit. The licence may be granted by the Excise Commissioner as per Rule 52(7) of the Tripura Excise (Fifteenth Amendment) Rules, 2018 in the prescribed form. The applicant shall be bound to conform to the wishes of the Excise Commissioner within a reasonable time to be fixed by the officer regarding any addition or alteration to the buildings, stills, vats or other permanent apparatus or plant which he considers necessary, whether before or after the final plans are submitted for the proper security of the revenue or to render illicit practices impracticable.</span></span></span></span></span></span></li>\n	<li><span><span><span><span><span><span>No addition or alteration to the buildings, stills or other permanent apparatus as shown in the plans finally submitted by the applicant shall be made without the previous sanction of the Excise Commissioner. When any such additions or alterations are made fresh plans must be submitted to the Excise Commissioner with a certificate from the concerned Collector of Excise that they are correct.</span></span></span></span></span></span></li>\n	<li><span><span><span><span><span><span><span>It will be opened to the Excise Commissioner to verify at any time any of the descriptions and plans above mentioned, and on proof of error, to require fresh ones to be submitted for sanction. Such verification may be made by any officer deputed for the purpose, and such officer shall be allowed full access to the premises. Sanction to the plans may be withheld until any point in respect of which they differ from plans already sanctioned has been rectified to the satisfaction of the Excise Commissioner. The Country liquor bottler shall be bound to carry out such rectification within a reasonable time to be fixed by the Excise Commissioner.</span></span></span></span></span></span></span></li>\n</ul>\n\n<ul>\n	<li><span><span><span><span><span><span><span>Security deposit</span></span><span><span>:- </span></span></span></span></span></span></span></li>\n</ul>\n\n<ol>\n	<li><span><span><span><span><span><span><span>Before the license to work the Country liquor bottling unit is granted by the Excise Commissioner, the Country liquor bottler shall give a security of Rs. 1,00,000/- (Rupees One Lakh) only as prescribed vide Sl. No. 5 of the Notification No.F.II-5(4)-EX/18/82-90 dated 14-01-2019 in cash or Government Promissory Notes for the due observance of the conditions of the license :</span></span></span></span></span></span></span></li>\n	<li><span><span><span><span><span><span><span>The Country liquor bottler shall also execute a bond in the prescribed form pledging the Country liquor bottling premises, stills, all apparatus and utensils employed in the manufacture of spirit and the stock-in-trade for the due discharge of all payments which may become due to the Government:</span></span></span></span></span></span></span></li>\n</ol>\n\n<p><span><span><span><span><span><span><span>       Provided that in lieu of so pledging the Country liquor bottling premises the Country liquor bottler may deposit Government Promissory Notes of such value as the Excise Commissioner may direct, and execute an indemnity bond of a value fixed by the Excise Commissioner.</span></span></span></span></span></span></span></p>', '<ul>\n	<li><span><span><span><span><span><span><span>The name or names, and the address or addresses, of the person or persons applying.</span></span></span></span></span></span></span></li>\n	<li><span><span><span><span><span><span><span>The purpose for which the Country liquor bottling unit is proposed to be opened, specifying in detail the nature of the business which the applicant desires to carry on therein.</span></span></span></span></span></span></span></li>\n	<li><span><span><span><span><span><span><span>The name of the place in which, the site on which and the building in which the Country liquor bottling unit is to be constructed or worked. Correct plan of the building which he intends to use or to construct for his Country liquor bottling unit, and a plan showing the position of stills, vats and other permanent apparatus therein, and a list of store-rooms, warehouse, etc. connected therewith. In this regard, a sketch shall be submitted along with the application.   </span></span></span></span></span></span></span></li>\n	<li><span><span><span><span><span><span><span>The number and full description of the stills, vats and other permanent apparatus which the applicant wishes to work or set up and the size and capacity of such stills, etc. In this regard, a Project report shall be submitted along with the application.  </span></span></span></span></span></span></span></li>\n	<li><span><span><span><span><span><span>The date from which, in the event of a license being granted to him, the applicant proposes to commence working the Country liquor bottling unit.</span></span></span></span></span></span></li>\n</ul>', '<ul>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Issuance of LoI – 25 (Twenty Five) days (CFE). </span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Approval for License - 25 (Twenty Five) days (CFO).</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Issuance of License – 05 (Five) days (CFO).</span></span></span></span></span></li>\n</ul>'),
(37, '<a href=\"/node/38230\" hreflang=\"en\">Excise-Import-Permit</a>', '', 0, '', 'Other Services', 'Excise', '<ul>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Import Fee – IMFL - @ Rs.20/-  per BKL.</span></span></span></span></span></li>\n</ul>\n\n<p><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">          BEER - @ Rs.10/- per BKL.</span></span></span></span></span></p>\n\n<ul>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Excise Duty -</span> <span><span><span>The User can view the rates and tariffs for Excise Duty at </span></span></span><a href=\"http://www.eabgari.tripura.gov.in\"><span><span>www.eabgari.tripura.gov.in</span></span></a>  </span></span></span></span></li>\n</ul>', 'Application for issuance of Import Permit for Foreign Liquor, Beer and Country Liquor', '', 0, '<ul>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Licensee of the Warehouse submits the application online to the Commissioner of Excise, Tripura, Gurkhabasti.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">The deficiencies in the application will be informed to the applicant.</span></span></span></span></span></li>\n</ul>\n\n<p><span><span><span><span><strong><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Processing of the Application:</span></strong></span></span></span></span></p>\n\n<ul>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">If the application is found in order, the Commissioner of Excise, Tripura send the application to the O/o the Collector of Excise (DM &amp; Collector) for verification.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">The O/o the Collector of Excise (DM &amp; Collector) forwards the verification report to the Commissioner of Excise, Tripura.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Order of Deposit is issued to the Applicant asking for payment of requisite Excise Duty and Import Fee.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Import Permit is issued to the applicant on realization of the Excise Duty and Import Fee.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">The Import permit is valid for maximum 90 (Ninety) days.</span></span></span></span></span></li>\n</ul>', '<ul>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Application to be submitted in the prescribed format </span><span><span><span>at </span></span></span><a href=\"http://www.eabgari.tripura.gov.in\"><span><span>www.eabgari.tripura.gov.in</span></span></a>  </span></span></span></span></li>\n</ul>', '<ul>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Sending the application to the Collector of Excise (DM &amp; Collector) for verification – 02 (Two) days. </span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Verification – 03 (Three) days.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Issuance of Deposit Order – 02 (Two) days.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Issuance of Import Permit – 03 (Three) days.</span></span></span></span></span></li>\n</ul>'),
(38, '<a href=\"/node/38229\" hreflang=\"en\">Excise-Warehouse-Retail</a>', '', 0, '', 'Consent for Operation', 'Excise', '<p><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Fixed by the Government as per Rule- 154(2) read with tender guideline dated 23-08-2019.</span></span></span></p>', 'LICENSE FOR WAREHOUSE, RETAIL FL SHOP &amp; CL SHOP', '', 0, '<ul>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Settlement of Warehouse, Retail FL Shop &amp; CL Shop is done through e-tender online portal.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Tender inviting authority is the Collector of Excise (DM &amp; Collector).</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Detailed NIT publish in the e-tender portal (</span><a href=\"http://www.tripuratenders.gov.in\"><span>www.tripuratenders.gov.in</span></a><span>).</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">e-tender open after minimum of 21 days of the publication.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Technical bid open first.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Field enquiry is done thereafter.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">After completion of technical bid process, financial bid is open.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">If the bid is found in order as per terms and condition of the tender, the Collector of Excise (DM &amp; Collector) sent to the Commissioner of Excise, Government of Tripura along with recommendation for Government approval.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">License is issued to the successful bidder after approval of the Government and on realization of license fees.</span></span></span></span></span></li>\n</ul>', '<ul>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">The bidders to be uploaded the documents required as per terms and condition of the tender publish at </span><a href=\"http://www.tripuratenders.gov.in\"><span>www.tripuratenders.gov.in</span></a></span></span></span></span></li>\n</ul>', '<ul>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Approval – 21 (Twenty One) working days (CFE) subject to condition there is no litigation.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Issuance of License – 05 (Five) working days (CFO) subject to condition there is no litigation.</span></span></span></span></span></li>\n</ul>'),
(39, '<a href=\"/node/38229\" hreflang=\"en\">Excise-Warehouse-Retail</a>', '', 0, '', 'Consent for Operation', 'Excise', '<p><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Fixed by the Government as per Rule- 154(2) read with tender guideline dated 23-08-2019.</span></span></span></p>', 'LICENSE FOR WAREHOUSE, RETAIL FL SHOP &amp; CL SHOP', '', 1, '<ul>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Settlement of Warehouse, Retail FL Shop &amp; CL Shop is done through e-tender online portal.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Tender inviting authority is the Collector of Excise (DM &amp; Collector).</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Detailed NIT publish in the e-tender portal (</span><a href=\"http://www.tripuratenders.gov.in\"><span>www.tripuratenders.gov.in</span></a><span>).</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">e-tender open after minimum of 21 days of the publication.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Technical bid open first.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Field enquiry is done thereafter.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">After completion of technical bid process, financial bid is open.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">If the bid is found in order as per terms and condition of the tender, the Collector of Excise (DM &amp; Collector) sent to the Commissioner of Excise, Government of Tripura along with recommendation for Government approval.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">License is issued to the successful bidder after approval of the Government and on realization of license fees.</span></span></span></span></span></li>\n</ul>', '<ul>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">The bidders to be uploaded the documents required as per terms and condition of the tender publish at </span><a href=\"http://www.tripuratenders.gov.in\"><span>www.tripuratenders.gov.in</span></a></span></span></span></span></li>\n</ul>', '<ul>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Approval – 21 (Twenty One) working days (CFE) subject to condition there is no litigation.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Issuance of License – 05 (Five) working days (CFO) subject to condition there is no litigation.</span></span></span></span></span></li>\n</ul>');
INSERT INTO `information_wizards` (`id`, `title`, `field_fee_structure_files`, `delta`, `field_noc_master_link`, `field_wizard_category`, `field_wizard_department`, `field_wizard_fee_text`, `field_wizard_noc_name`, `field_wizard_notification`, `delta_1`, `field_wizard_process`, `field_wizard_required_documents`, `field_wizard_timeline`) VALUES
(40, '<a href=\"/node/38228\" hreflang=\"en\">Excise-Brand-Label</a>', '', 0, '', 'Consent for Operation', 'Excise', '<ul>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Registration fees – Rs.80,000/- (Rupees Eighty Thousand) only annually per brand per volume.</span></span></span></span></span></li>\n	<li><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>Renewal fees – Rs.50,000/- (Rupees Fifty Thousand) only annually per brand per volume.</span></span></span></li>\n</ul>', 'Application for Brand/Label Registration of Liquor', '', 0, '<p><span><span><span><span><strong><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Application for Brand/Label Registration of Liquor:</span></strong></span></span></span></span></p>\n\n<ul>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Application shall be made online only by the Company (Brand Owner) along with all supporting documents.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Application for registration of liquor brand, label and capsules etc. shall be made to the Commissioner of Excise, Tripura at least two week prior to its sale or offer of sale.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Application for renewal for liquor brand, label and capsules etc. shall be made to the Commissioner of Excise, Tripura within the fifteenth day of the month of March each year.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">The applications are pre-scrutinized to verify that the application is in full form with all required enclosures.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">The deficiencies in the application will be informed to the applicant.</span></span></span></span></span></li>\n</ul>\n\n<p><span><span><span><span><strong><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Processing of the Application:</span></strong></span></span></span></span></p>\n\n<ul>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">If the application is found in order, the Commissioner of Excise, Tripura will allocate an inspector to inspect the submitted brand, labels and capsules etc.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">The inspector then submits the report with his/her opinion to the Department.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">On being satisfied the Commissioner of Excise, Tripura shall fix necessary registration/renewal fees whichever is applicable and realize the same from the concerned company.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">On received of the fees, necessary Order/Notification will be issued for registration/renewal of the liquor brand, labels and capsules etc.</span></span></span></span></span></li>\n</ul>\n\n<p><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>The Notification of registration/renewal of liquor granted shall be valid for a financial year i.e. 1st April to 31st March, 2020.</span></span></span></p>', '<ol>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Undertaking that the company shall be bound to supply its products (intoxicant) which are duly registered in Tripura to all Licensed Bonded Warehouse of the State, subject to the payment of the cost of the products and fulfilment of business policy/terms and conditions of this Company.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Capsules of every volume which are to be registered/renewed shall be submitted for the purpose of enquiry.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Notary Affidavit regarding submission of Utilization Certificate on monthly basis to the Collector of Excise and affixing of holograms on each and every bottle of IMFL, Beer and Country Liquor etc.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Particulars to be shown on the labels :-</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">The labels must specify the nature of the liquor contained therein, i.e. whether it is Whisky, Brandy, Gin, Rum, Country Liquor or any other alcoholic beverages.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">The name and full address of the distiller/compounder/blender/brewer/bottler etc. where it is bottled and country of origin.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Labels should be inscripted with the Statutory Warning saying that “Consumption of liquor is injurious to health”.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">The warning at point number c) above shall also be printed in Kokborok and Bengali language.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Labels should also be printed with words i.e. “Not for sale to persons below 21 years of age”.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">For the foreign liquor and country liquor for sale in Tripura shall be printed with “For sale in Tripura only”.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">For the liquor to be exported outside Tripura shall be printed with “Not for sale in Tripura”.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Label should be printed with Maximum Retail Price (MRP), date of manufacture and expiry in case of Can Beer/Pet bottle.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Every label shall be authenticated by the applicant with his seal, signature and year of registration/renewal.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">The brand name and the alcoholic strength of the liquor products and the measures in litre it is proposed to be sold.</span></span></span></span></span></li>\n	<li><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">10 numbers of Labels of each brands and volume to be submitted along with the application having duly authenticated by the applicant in the backside of the each labels.  </span></span></span></span></span></li>\n</ol>', '<p><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">21 (Twenty One) days.</span></span></span></span></span></p>'),
(41, '<a href=\"/node/441276\" hreflang=\"en\">L4-revised-factory-drawing</a>', '', 0, '', 'Other Services', 'Factories Organisation', '<p><strong>Flow Chart of Stagewise Details with Cost and Time</strong></p>\n\n<table border=\"1\" class=\"MsoTableGrid\" style=\"margin-left:37px; border-collapse:collapse; border:1px solid\" width=\"100%\">\n	<thead>\n		<tr>\n			<th style=\"width:35px; padding:7px; text-align:center;\">Sl.</th>\n			<th style=\"width:280px; padding:7px; text-align:center;\">Stage</th>\n			<th style=\"width:130px; padding:7px; text-align:center;\">Timeline</th>\n			<th style=\"width:120px; padding:7px; text-align:center;\">Fees</th>\n		</tr>\n	</thead>\n	<tbody>\n		<tr>\n			<td style=\"padding:7px; text-align:center;\">1</td>\n			<td style=\"padding:7px;\">Application submission by applicant</td>\n			<td style=\"padding:7px; text-align:center;\">0 Day</td>\n			<td style=\"padding:7px; text-align:center;\">Rs. 150/-</td>\n		</tr>\n		<tr>\n			<td style=\"padding:7px; text-align:center;\">2</td>\n			<td style=\"padding:7px;\">Dealing Assistant</td>\n			<td style=\"padding:7px; text-align:center;\">03 Days</td>\n			<td style=\"padding:7px; text-align:center;\">---</td>\n		</tr>\n		<tr>\n			<td style=\"padding:7px; text-align:center;\">3</td>\n			<td style=\"padding:7px;\">Investigator</td>\n			<td style=\"padding:7px; text-align:center;\">07 Days</td>\n			<td style=\"padding:7px; text-align:center;\">---</td>\n		</tr>\n		<tr>\n			<td style=\"padding:7px; text-align:center;\">4</td>\n			<td style=\"padding:7px;\">Inspector of Factories</td>\n			<td style=\"padding:7px; text-align:center;\">04 Days</td>\n			<td style=\"padding:7px; text-align:center;\">---</td>\n		</tr>\n		<tr>\n			<td style=\"padding:7px; text-align:center;\">5</td>\n			<td style=\"padding:7px;\">Investigating Officer / Asst. Investigating Officer</td>\n			<td style=\"padding:7px; text-align:center;\">04 Days</td>\n			<td style=\"padding:7px; text-align:center;\">---</td>\n		</tr>\n		<tr>\n			<td style=\"padding:7px; text-align:center;\">6</td>\n			<td style=\"padding:7px;\">Chief Inspector of Factories &amp; Boilers</td>\n			<td style=\"padding:7px; text-align:center;\">03 Days</td>\n			<td style=\"padding:7px; text-align:center;\">---</td>\n		</tr>\n		<tr>\n			<td colspan=\"2\" style=\"padding:7px; text-align:right; font-weight:bold;\">Total</td>\n			<td style=\"padding:7px; text-align:center; font-weight:bold;\">21 Days</td>\n			<td style=\"padding:7px; text-align:center;\">---</td>\n		</tr>\n	</tbody>\n</table>\n\n<p> </p>\n\n<p><strong>Risk Category</strong></p>\n\n<table border=\"1\" style=\"width:100%; border-collapse:collapse\">\n	<thead>\n		<tr>\n			<th style=\"width:35px; border-top:1px solid black; border-bottom:1px solid black; padding:0cm 7px 0cm 7px; text-align:center; font-size:11pt; font-family:Times New Roman,serif;\">Sl. No.</th>\n			<th style=\"width:280px; border-top:1px solid black; border-bottom:1px solid black; padding:0cm 7px 0cm 7px; text-align:center; font-size:11pt; font-family:Times New Roman,serif;\">Type of Risk</th>\n			<th style=\"width:286px; border-top:1px solid black; border-bottom:1px solid black; padding:0cm 7px 0cm 7px; text-align:center; font-size:11pt; font-family:Times New Roman,serif;\">Factories/Industries</th>\n			<th style=\"width:286px; border-top:1px solid black; border-bottom:1px solid black; padding:0cm 7px 0cm 7px; text-align:center; font-size:11pt; font-family:Times New Roman,serif;\">Documents/Process/Fees etc.</th>\n		</tr>\n	</thead>\n	<tbody>\n		<tr>\n			<td style=\"border-bottom:1px solid black; width:35px; padding:0cm 7px 0cm 7px; border-right:1px solid black; border-left:1px solid black\" valign=\"top\">\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Times New Roman,serif\">1</span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:280px; padding:0cm 7px 0cm 7px; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Times New Roman,serif\">High Risk</span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:286px; padding:0cm 7px 0cm 7px; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Times New Roman,serif\">1) All Major accident Hazard Factories(MAH units)<br />\n			2) All factories having “Hazardous Process”<br />\n			3) All factories more than 50 workers<br />\n			4) All Factories where there is the risk of workers as mentioned in Third Schedule of the Factories Act, 1948<br />\n			5) All Factories covered under Section 87 of the Factories Act, 1948 &amp; Rule 160 of the Tripura Factories Rules, 2007, employing more than 20 workers<br />\n			6) All factories where motive power is more than 100 H.P.</span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:286px; padding:0cm 7px 0cm 7px; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Times New Roman,serif\">As per Sl. No. 1</span></span></p>\n			</td>\n		</tr>\n		<tr>\n			<td style=\"border-bottom:1px solid black; width:35px; padding:0cm 7px 0cm 7px; border-right:1px solid black; border-left:1px solid black\" valign=\"top\">\n			<p><span style=\"font-size:11pt\"><span style=\"font-family:Times New Roman,serif\">2</span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:280px; padding:0cm 7px 0cm 7px; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"font-family:Times New Roman,serif\">Medium Risk</span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:286px; padding:0cm 7px 0cm 7px; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p s