\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"text-justify:inter-ideograph\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Industrial Estate</span></span></span></span></span></span></p>\n			</td>\n			<td rowspan=\"3\" style=\"border-bottom:1px solid black; width:286px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p style=\"text-align:justify\"><strong>Documents to be submitted with the Application as per Sl. No.1(c)</strong></p>\n			</td>\n		</tr>\n		<tr>\n			<td style=\"border-bottom:1px solid black; width:35px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:1px solid black\" valign=\"top\">\n			<p><span style=\"font-size:11pt\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">2</span></span></span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:280px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"text-justify:inter-ideograph\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Urban</span></span></span></span></span></span></p>\n			</td>\n		</tr>\n		<tr>\n			<td style=\"border-bottom:1px solid black; width:35px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:1px solid black\" valign=\"top\">\n			<p><span style=\"font-size:11pt\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">3</span></span></span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:280px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"text-justify:inter-ideograph\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Rural</span></span></span></span></span></span></p>\n			</td>\n		</tr>\n	</tbody>\n</table>\n\n<p> </p>\n\n<p> </p>\n\n<p><strong><span style=\"font-size:11pt\"><span style=\"font-family:Times New Roman,serif\">Investor:</span></span></strong></p>\n\n<table border=\"1\" style=\"width:100%; border-collapse:collapse\">\n	<thead>\n		<tr>\n			<th style=\"width:280px; border-top:1px solid black; border-bottom:1px solid black; padding:0cm 7px 0cm 7px; text-align:center; font-size:11pt; font-family:Times New Roman,serif;\">Investor</th>\n			<th style=\"width:286px; border-top:1px solid black; border-bottom:1px solid black; padding:0cm 7px 0cm 7px; text-align:center; font-size:11pt; font-family:Times New Roman,serif;\">Domestic Investor</th>\n			<th style=\"width:286px; border-top:1px solid black; border-bottom:1px solid black; padding:0cm 7px 0cm 7px; text-align:center; font-size:11pt; font-family:Times New Roman,serif;\">Foreign Investor</th>\n			<th style=\"width:286px; border-top:1px solid black; border-bottom:1px solid black; padding:0cm 7px 0cm 7px; text-align:center; font-size:11pt; font-family:Times New Roman,serif;\">Documents to be submitted with the Application</th>\n		</tr>\n	</thead>\n	<tbody>\n		<tr>\n			<td style=\"border:1px solid black; padding:0cm 7px 0cm 7px; text-align:center; font-size:11pt; font-family:Times New Roman,serif;\">Investor</td>\n			<td style=\"border:1px solid black; padding:0cm 7px 0cm 7px; text-align:center; font-size:11pt; font-family:Times New Roman,serif;\">Documents to be submitted with the Application as per Sl. No.1(C)</td>\n			<td style=\"border:1px solid black; padding:0cm 7px 0cm 7px; text-align:center; font-size:11pt; font-family:Times New Roman,serif;\">Documents to be submitted with the Application as per Sl. No.1(c) and permission from the authority of Govt. of India</td>\n			<td style=\"border:1px solid black; padding:0cm 7px 0cm 7px; text-align:center; font-size:11pt; font-family:Times New Roman,serif;\">Documents required as per the specified Sl. No.</td>\n		</tr>\n	</tbody>\n</table>\n\n<p> </p>\n\n<p><strong>Fees payable for grant of Factory Licence and renewal of Factory License</strong></p>\n\n<table border=\"1\" class=\"MsoTableGrid\" style=\"margin-left:37px; border-collapse:collapse; border:1px solid\" width=\"100%\">\n	<tbody>\n		<tr>\n			<td style=\"border-bottom:1px solid black; width:35px; padding:0cm 7px 0cm 7px; border-top:1px solid black; border-right:1px solid black; border-left:1px solid black\" valign=\"top\">\n			<p align=\"center\" style=\"text-align:center\"><span style=\"font-size:11pt\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><b><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Sl.</span></span></b></span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:280px; padding:0cm 7px 0cm 7px; border-top:1px solid black; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p align=\"center\" style=\"text-align:center\"><span style=\"font-size:11pt\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><b><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Description</span></span></b></span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:286px; padding:0cm 7px 0cm 7px; border-top:1px solid black; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p align=\"center\" style=\"text-align:center\"><span style=\"font-size:11pt\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><b><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Fees payable</span></span></b></span></span></span></p>\n			</td>\n		</tr>\n		<tr>\n			<td style=\"border-bottom:1px solid black; width:35px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:1px solid black\" valign=\"top\">\n			<p><span style=\"font-size:11pt\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">1</span></span></span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:280px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"text-justify:inter-ideograph\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Approval of plan and permission to construct/extend/or take into use any building as a factory</span></span></span></span></span></span></p>\n			</td>\n			<td rowspan=\"3\" style=\"border-bottom:1px solid black; width:286px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"text-justify:inter-ideograph\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Rs.150.00</span></span></span></span></span></span></p>\n			</td>\n		</tr>\n		<tr>\n			<td style=\"border-bottom:1px solid black; width:35px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:1px solid black\" valign=\"top\">\n			<p><span style=\"font-size:11pt\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">2</span></span></span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:280px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"text-justify:inter-ideograph\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Approval of Revised Plan Drawings</span></span></span></span></span></span></p>\n			</td>\n		</tr>\n		<tr>\n			<td style=\"border-bottom:1px solid black; width:35px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:1px solid black\" valign=\"top\">\n			<p><span style=\"font-size:11pt\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">3</span></span></span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:280px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"text-justify:inter-ideograph\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Amendment of Factory Licence</span></span></span></span></span></span></p>\n			</td>\n		</tr>\n		<tr>\n			<td style=\"border-bottom:1px solid black; width:35px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:1px solid black\" valign=\"top\">\n			<p><span style=\"font-size:11pt\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">4</span></span></span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:280px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"text-justify:inter-ideograph\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Registration of Factory under the Factories Act, 1948</span></span></span></span></span></span></p>\n			</td>\n			<td rowspan=\"2\" style=\"border-bottom:1px solid black; width:286px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"text-justify:inter-ideograph\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">As per Schedule A, B &amp; C of Tripura Factories Rules, 2007.</span></span></span></span></span></span></p>\n			</td>\n		</tr>\n		<tr>\n			<td style=\"border-bottom:1px solid black; width:35px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:1px solid black\" valign=\"top\">\n			<p><span style=\"font-size:11pt\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">5</span></span></span></span></span></p>\n			</td>\n			<td style=\"border-bottom:1px solid black; width:280px; padding:0cm 7px 0cm 7px; border-top:none; border-right:1px solid black; border-left:none\" valign=\"top\">\n			<p style=\"text-align:justify\"><span style=\"font-size:11pt\"><span style=\"text-justify:inter-ideograph\"><span style=\"line-height:normal\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Renewal of Factory License under the Factories Act, 1948</span></span></span></span></span></span></p>\n			</td>\n		</tr>\n	</tbody>\n</table>\n', 'Application for Approval of plan and permission to construct/extend/or take into use any building as a factory', '', 0, '<p><strong>Submission of Application: </strong></p>\n\n<ul>\n	<li>The Entrepreneur shall submit application on-line through <strong>SWAAGAT </strong>(https://swaagat.tripura.gov.in).</li>\n	<li>The application is pre-scrutinized online at SWAAGAT<strong> </strong>to verify that the application is in full form with all required enclosures.</li>\n	<li>The deficiencies, if any, in the application will be informed by the scrutinizing officers to the applicant.``</li>\n</ul>\n\n<p><strong>Processing of the Application: </strong></p>\n\n<ul>\n	<li>If the application is found to be in order, the department will allocate an inspector to conduct an Inspection.</li>\n	<li>The inspector then uploads the inspection report to the Department.</li>\n	<li>Based on the report, if all are in order, Chief Inspector of Factories &amp; Boilers will sign and upload the approval in SWAAGAT portal.</li>\n	<li>The entrepreneur can view and download the digital copy of the approval in his login.</li>\n</ul>', '<ol>\n	<li>Plan drawing of factory showing details as per guidelines of the department.</li>\n	<li>Detailed building plan.</li>\n	<li>Process Flow chart and write-up.</li>\n	<li>List of raw materials to be used and intermediate &amp; finished products.</li>\n	<li>Motive Power in H.P./KW</li>\n	<li>Details of arrangements for the disposal of Trade waste and effluents.</li>\n	<li>Land document – Sale deed/ Lease deed.</li>\n	<li>\n	<p>Documents related to Occupier:</p>\n\n	<ul>\n		<li>\n		<p>In case of partnership – Valid partnership deed &amp; list of partners.</p>\n		</li>\n		<li>\n		<p>In case of public or private limited company – Articles of Association, List of Directors, certificate of incorporation of the company, Resolution of Board of Directors, etc.</p>\n		</li>\n		<li>\n		<p>In case of private company – List of shareholders.</p>\n		</li>\n		<li>\n		<p>In case of factory owned by Central or State govt. undertaking – Govt. order for having appointed the Occupier.</p>\n		</li>\n		<li>\n		<p>In case of Co-op. Society - Registered document, Resolution of Board, list of shareholders, President/Secretary.</p>\n\n		<p>• Citizenship Certificate or Permanent Resident Certificate.</p>\n\n		<p></p>\n\n		<p>• PAN card.</p>\n\n		<p>• Aadhaar card.</p>\n\n		<p>• Passport size photograph with signature.</p>\n\n		<p>• Land diversion certificate from competent authority, if applicable,</p>\n\n		<p>• Valid Pollution Consent.</p>\n\n		<p>• Forest Trade Licence and other NOCs, if applicable.</p>\n\n		<p>• NOCs of competent authority, if applicable, etc.</p>\n\n		<p>• For Hazardous Industries:</p>\n\n		<p>- Proposed inventories of Chemicals used and stored.</p>\n\n		<p>- On-site Emergency Plan &amp;Off-site emergency plan (to be approved by the department).</p>\n\n		<p>• Such other particulars as the Chief Inspector of Factories &amp; Boilers may require.</p>\n		</li>\n	</ul>\n	</li>\n</ol>', '<p><span><span><span>Factory Plan Approval: 21 days</span></span></span></p>\n'),
(45, '<a href=\"/node/38237\" hreflang=\"en\">Fire-Occupancy</a>', '', 0, '<a href=\"/node/19500\" hreflang=\"en\">CFO-FDPN1</a>', 'Consent for Operation', 'Fire Services', '', 'Occupancy Certificate', '', 0, '<p>Procedure:<br />\n~ Submitting application through SWAAGAT (<a href=\"https://swaagat.tripura.gov.in\">https://swaagat.tripura.gov.in</a>)  with required input in respect of service.<br />\n~ Uploading required documents/ plan etc.<br />\n~ Application will be automatically endorsed to concerned district level officer.<br />\n~ Status of application will notify through SMS.<br />\n~ On approval of State level authority applicant will able to download Clearance/ NOC from the system</p>', '<ul>\n	<li>Building Plan mentioning fi re fighting arrangements</li>\n	<li>Business documents</li>\n	<li>Land documents</li>\n</ul>', '<p>14 Days</p>'),
(46, '<a href=\"/node/38236\" hreflang=\"en\">Fire-NOC</a>', '', 0, '<a href=\"/node/13986\" hreflang=\"en\">CFE-FDPN1</a>', 'Consent for Establishment', 'Fire Services', '<p>Nil</p>', 'Fire License / NOC', '', 0, '<p>Procedure:<br />\n~ Submitting application through SWAAGAT (<a href=\"https://swaagat.tripura.gov.in\">https://swaagat.tripura.gov.in</a>)  with required input in respect of service.<br />\n~ Uploading required documents/ plan etc.<br />\n~ Application will be automatically endorsed to concerned district level officer.<br />\n~ Status of application will notify through SMS.<br />\n~ On approval of State level authority applicant will able to download Clearance/ NOC from the system</p>', '<ul>\n	<li>Building Plan mentioning fi re fighting arrangements</li>\n	<li>Business documents</li>\n	<li>Land documents</li>\n	<li>Affidavit I additional documents as when required.</li>\n</ul>', '<p>14 Days</p>'),
(47, '<a href=\"/node/38246\" hreflang=\"en\">Labour-Contractor-ISMW</a>', '', 0, '<a href=\"/node/36197\" hreflang=\"en\">SPC-DL3</a>', 'Special Services', 'Directorate of Labour', '<p><strong>Fees payable for grant of Factory Licence and renewal of Factory Licence and Boilers Licence</strong></p>\n\n<table border=\"1\" class=\"MsoTableGrid\" style=\"margin-left:37px; border-collapse:collapse; border:1px solid\" width=\"100%\">\n	<thead>\n		<tr>\n			<th style=\"width: 5%; text-align: center; padding: 5px;\">Sl.</th>\n			<th style=\"width: 50%; text-align: center; padding: 5px;\">Description</th>\n			<th style=\"width: 45%; text-align: center; padding: 5px;\">Fees payable</th>\n		</tr>\n	</thead>\n	<tbody>\n		<tr>\n			<td style=\"text-align: center; padding: 5px;\">1</td>\n			<td style=\"text-align: justify; padding: 5px;\">Approval of plan and permission to construct/extend/or take into use any building as a factory</td>\n			<td style=\"text-align: justify; padding: 5px;\">Rs.150.00</td>\n		</tr>\n		<tr>\n			<td style=\"text-align: center; padding: 5px;\">2</td>\n			<td style=\"text-align: justify; padding: 5px;\">Registration of Factories under the Factories Act, 1948</td>\n			<td rowspan=\"2\" style=\"text-align: justify; padding: 5px;\">As per Schedule A, B &amp; C of Tripura Factories Rules, 2007.</td>\n		</tr>\n		<tr>\n			<td style=\"text-align: center; padding: 5px;\">3</td>\n			<td style=\"text-align: justify; padding: 5px;\">Renewal of Factories Registration under the Factories Act, 1948</td>\n		</tr>\n		<tr>\n			<td style=\"text-align: center; padding: 5px;\">4</td>\n			<td style=\"text-align: justify; padding: 5px;\">Amendment of Factory Licence</td>\n			<td style=\"text-align: justify; padding: 5px;\">Rs.150.00</td>\n		</tr>\n		<tr>\n			<td style=\"text-align: center; padding: 5px;\">5</td>\n			<td style=\"text-align: justify; padding: 5px;\">Transfer of Factory Licence</td>\n			<td style=\"text-align: justify; padding: 5px;\">@25% of fees originally payable for the grant or renewal of the licence subject to a minimum of Rs.150.00 and maximum of Rs.750.00</td>\n		</tr>\n		<tr>\n			<td style=\"text-align: center; padding: 5px;\">6</td>\n			<td style=\"text-align: justify; padding: 5px;\">Loss of Factory Licence</td>\n			<td style=\"text-align: justify; padding: 5px;\">@25% of fees originally payable for the grant or renewal of the licence subject to a minimum of Rs.150.00 and maximum of Rs.750.00</td>\n		</tr>\n	</tbody>\n</table>\n', 'License /renewal of License under the Inter- State Migrant Workmen ( RE&amp;CS) Act, 1979.', '', 0, '<p><span><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">i). Applicant is to submit the application Form ( form – V)  along with required documents, proof   of fee     deposited and Security Money.</span></span></span></span></span></span></p>\n\n<p><span><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">ii). verification of the document &amp; Spot Inspection if require.</span></span></span></span></span></span></p>\n\n<p><span><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">iii) After having satisfaction ,application with its enclosures will be forwarded  to the  Licensing  Authority </span></span></span></span></span></span></p>\n\n<p><span><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">iv).</span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span> Any dissatisfaction with application to be  communicated to the applicant.</span></span></span></span></span></span></span></p>\n\n<p><span><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">v). Received corrected application submitted to licensing   Authority.</span></span></span></span></span></span></p>\n\n<p><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>vii). License issued .</span></span></span></p>', '<p><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">i). Principal Employer Certificate in Form –VI or Work order or Agreement with Principal Employer or Enlistment copy of Govt.  Department  ( Government of Tripura)</span></span></span></span></span></p>\n\n<p><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">ii).  Proof of License fee &amp; Security deposited  </span></span></span></span></span></p>\n\n<p><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">iv) PAN Card copy</span></span></span></span></span></p>\n\n<p><span><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">v). In case of partner- partnership deed</span></span></span></span></span></span></p>\n\n<p><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>vi). In case of individual :- Proof of date of birth  </span></span></span></p>', '<p><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>30 days</span></span></span></p>');
INSERT INTO `information_wizards` (`id`, `title`, `field_fee_structure_files`, `delta`, `field_noc_master_link`, `field_wizard_category`, `field_wizard_department`, `field_wizard_fee_text`, `field_wizard_noc_name`, `field_wizard_notification`, `delta_1`, `field_wizard_process`, `field_wizard_required_documents`, `field_wizard_timeline`) VALUES
