(51, '<a href=\"/node/38242\" hreflang=\"en\">Labour-Registration-CL</a>', '', 0, '<a href=\"/node/13639\" hreflang=\"en\">CFE-DOL1</a>', 'Consent for Establishment', 'Directorate of Labour', '<p><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Fee depend upon  number of workers. </span></span></span></span></span></p>\n\n<p><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">(a) is 5 Rs.200</span></span></span></span></span></p>\n\n<p><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"> (b) exceeds 5 but does not exceed 10 Rs 300/- </span></span></span></span></span></p>\n\n<p><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">(c) exceeds 10 but does not exceed 20 Rs 400/- </span></span></span></span></span></p>\n\n<p><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">(d) exceeds 20 but does not exceed 50 Rs 800/- </span></span></span></span></span></p>\n\n<p><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">(e) exceeds 50 but does not exceed 100 Rs 1200</span></span></span></span></span></p>\n\n<p><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"> (f)_ exceeds-100 but does not exceed 200 Rs 1600/- </span></span></span></span></span></p>\n\n<p><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>(g) exceeds 200 Rs 2000/-</span></span></span></p>', 'Registration under the Contract Labour ( Regulation and Abolition) Act, 1970 ', '', 0, '<p><span><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">i) Applicant is to submit the application Form ( form – I)  along with required documents  and  proof   of fee deposited </span></span></span></span></span></span></p>\n\n<p><span><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>ii). Verification of the document &amp; Spot  Inspection if require .</span></span></span></span></span></span></span></p>\n\n<p><span><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>iii). After having  satisfaction ,application with its  enclosures will be   forwarded to the  Registering   Authority </span></span></span></span></span></span></span></p>\n\n<p><span><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>iv) Any  dissatisfaction with application to be  communicated to the    applicant.</span></span></span></span></span></span></span></p>\n\n<p><span><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>v). Received corrected application submitted to Registering Authority.</span></span></span></span></span></span></span></p>\n\n<p><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>vii). Registration issued.</span></span></span></p>', '<p><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">i). <span>Proof of fee deposited.</span></span></span></span></span></span></p>\n\n<p><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>ii) PAN Card copy</span></span></span></span></span></span></p>\n\n<p><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>iii). In case of partner- partnership deed</span></span></span></span></span></span></p>\n\n<p><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>iv) In case of Government Department – Government order</span></span></span></span></span></span></p>', '<p><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>30 days</span></span></span></p>'),
(52, '<a href=\"/node/38241\" hreflang=\"en\">Labour-Registration-ISMW</a>', '', 0, '<a href=\"/node/13946\" hreflang=\"en\">CFE-DOL2</a>', 'Consent for Establishment', 'Directorate of Labour', '<p><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">Fee depend upon  number of workers. </span></span></span></span></span></p>\n\n<p><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">(a) is 5 but does not exceed 50  fee Rs.500/-</span></span></span></span></span></p>\n\n<p><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">(b) exceeds 50 but does not exceed 100 Rs.1,000/- </span></span></span></span></span></p>\n\n<p><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>(c) exceeds 200 Rs.2,ooo</span></span></span></p>', 'Registration under the Inter- State Migrant Workmen ( RE&amp;CS) Act, 1979 ', '', 0, '<p><span><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">i). Applicant is to submit the application Form ( form – I)  along with required documents , proof    of fee </span></span></span></span></span></span></p>\n\n<p><span><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>ii). Verification of the document &amp; Spot  Inspection if require.</span></span></span></span></span></span></span></p>\n\n<p><span><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>iii). After having  satisfaction ,application with its  enclosures will be   forwarded to the  Registering   Authority </span></span></span></span></span></span></span></p>\n\n<p><span><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>iv) Any dissatisfaction with application to be communicated to the    applicant.</span></span></span></span></span></span></span></p>\n\n<p><span><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span>v). Received corrected application submitted to Registering Authority.</span></span></span></span></span></span></span></p>\n\n<p><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>vi). Registration issued.</span></span></span></p>', '<p><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">i ) Proof of fee deposit .</span></span></span></span></span></p>\n\n<p><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">ii) PAN Card copy</span></span></span></span></span></p>\n\n<p><span><span><span><span><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\">iii). In case of partner- partnership deed</span></span></span></span></span></p>\n\n<p><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>iv) In case of Government Department – Government order</span></span></span></p>', '<p><span lang=\"EN-IN\" xml:lang=\"EN-IN\" xml:lang=\"EN-IN\"><span><span>30 days</span></span></span></p>');
